// Contenido del estudio del Evangelio de Mateo — datos compartidos de la app

export interface GreekTerm {
  word: string;
  greek: string;
  translit: string;
  gloss: string;
}

export interface ChapterBlock {
  ref: string;
  text: string;
  commentary: string;
  greek: GreekTerm[];
}

export interface ChapterContext {
  title: string;
  body: string;
}

export interface ChapterContentEntry {
  title: string;
  intro: string;
  blocks: ChapterBlock[];
  reflection: string;
  context: ChapterContext | null;
}

export interface Discourse {
  id: string;
  name: string;
  chapters: number[];
  summary: string;
}

export interface Section {
  id: string;
  name: string;
  range: [number, number];
}

export interface Character {
  name: string;
  category: string;
  chapters: number[];
  blurb: string;
}

export interface MapPlace {
  name: string;
  x: number;
  y: number;
  region: string;
  note: string;
  chapters: number[];
}

export interface ContextTopic {
  id: string;
  theme: string;
  title: string;
  body: string;
}

