export function sectionFor(n: number): Section | undefined {
  return SECTIONS.find((s) => n >= s.range[0] && n <= s.range[1]);
}

export const COMPLETED_RANGE: [number, number] = [1, 11];
export function isCompleted(n: number): boolean {
  return n >= COMPLETED_RANGE[0] && n <= COMPLETED_RANGE[1];
}

const g = (word: string, greek: string, translit: string, gloss: string): GreekTerm => ({ word, greek, translit, gloss });

export const CHAPTER_CONTENT: Record<number, ChapterContentEntry> = {
  1: {
    title: 'Genealogía: honor y gracia',
    intro: 'Mateo abre su evangelio no con un relato de acción sino con una lista de nombres. En el mundo bíblico, una genealogía no era un simple registro familiar: servía para demostrar origen, honor y herencia. Mateo la organiza en tres bloques de catorce generaciones desde Abraham hasta Jesús, pasando por David — y lo que revela es tan sorprendente como la inclusión de cuatro mujeres marcadas por escándalo en una lista que la costumbre reservaba solo a hombres.',
    blocks: [
      { ref: '1:1', text: 'Libro de la genealogía de Jesucristo, hijo de David, hijo de Abraham.', commentary: 'Abraham recibió la promesa de que por su descendencia serían benditas todas las naciones; David, la de un reino eterno pese a ser un rey profundamente imperfecto. Mateo presenta a Jesús como el cumplimiento de ambas: Hijo de David, el Rey prometido, cuyo reino no tendrá fin.', greek: [g('genealogía', 'γένεσις', 'génesis', 'origen, principio — el mismo término que abre el libro de Génesis en la Septuaginta griega')] },
      { ref: '1:2-17', text: '...Judá engendró de Tamar a Fares y a Zara... y Salomón engendró a Roboam... Reyes de Judá.', commentary: 'Mateo organiza la genealogía en tres bloques de catorce generaciones, y no oculta el pecado de sus protagonistas. Judá es hipócrita, abusa de su autoridad familiar y está dispuesto a matar por el mismo pecado que él cometió; David es mujeriego y asesino; Salomón cae en lujuria descontrolada e idolatría, sabio intelectualmente pero débil espiritualmente; Jacob es estafador y manipulador; muchos de los reyes de Judá fueron idólatras, violentos e injustos. El Mesías no surge de una línea humana impecable, sino de una historia profundamente quebrada.', greek: [] },
      { ref: '1:2-17', text: '...Abraham engendró a Isaac... y Booz engendró de Rut a Obed.', commentary: 'Junto a los hombres marcados por el pecado aparecen otros que, sin ser perfectos, respondieron a Dios con fe: Abraham dejó su tierra por obediencia y confió en promesas humanamente imposibles; Isaac tuvo una vida silenciosa y constante, la fe perseverante que no se destaca por grandes hazañas; Booz fue justo, íntegro y actuó como redentor legal de Rut. Jesús no provenía de una familia perfecta, sino de una genealogía mixta — fieles y quebrados, gente común y reyes — que no lo limita, como tampoco nos determina a nosotros nuestra propia historia familiar.', greek: [] },
      { ref: '1:3,5,6', text: '...Judá engendró de Tamar a Fares... Salmón engendró de Rahab a Booz... y a Obed engendró de Rut... y David engendró de la que fue mujer de Urías a Salomón.', commentary: 'Las genealogías eran transmitidas por hombres; que Mateo incluya cuatro mujeres, y que ninguna tenga una historia "prolija", es una ruptura radical. Tamar se disfrazó de prostituta para que Judá cumpliera con ella la ley del levirato después de que este la abandonara; cuando Judá, sin saber que era ella, ordenó matarla por su embarazo, Tamar mostró las pruebas que él mismo le había dado y Judá reconoció: "ella es más justa que yo". Rahab era una prostituta cananea de Jericó que protegió a los espías de Josué arriesgando su vida, con una fe que se resume en "sé que el Señor su Dios es el verdadero". Rut era una moabita pagana, viuda y pobre, que eligió dejar su tierra y sus dioses por Noemí y por el Dios de Israel, y terminó casada con Booz.', greek: [] },
      { ref: '1:6', text: '...y David engendró de la que fue mujer de Urías a Salomón.', commentary: 'Betsabé, esposa de Urías —un soldado fiel—, ni siquiera es nombrada: se la identifica por su primer esposo. David la vio, la mandó traer y se acostó con ella; para encubrir el embarazo mandó matar a Urías y luego la tomó por esposa. Mateo no la excluye ni suaviza la historia al mencionarla en la genealogía del Mesías.', greek: [] },
      { ref: '1:18-19', text: 'María, desposada con José, se halló que había concebido del Espíritu Santo, antes que se juntasen. José, su marido, como era justo, y no quería infamarla, quiso dejarla secretamente.', commentary: 'María era una joven de aproximadamente quince años, comprometida con José, y aparece embarazada sin explicación humana disponible para él. José tenía derecho legal a exponerla públicamente —lo que, según la ley judía, podía costarle la vida a ella—, pero elige dejarla en secreto. Por eso el texto lo llama "justo": la justicia real, en este caso, se expresa como misericordia y no como cumplimiento estricto de la ley.', greek: [] },
      { ref: '1:20-21', text: 'Un ángel del Señor le apareció en sueños... "José, hijo de David, no temas recibir a María tu mujer, porque lo que en ella es engendrado, del Espíritu Santo es. Y dará a luz un hijo, y llamarás su nombre JESÚS, porque él salvará a su pueblo de sus pecados."', commentary: 'El ángel confirma lo que humanamente sonaba imposible de creer: María no le fue infiel. Mateo pone primero a cuatro mujeres con historias comprometedoras —prostitutas, extranjeras, señaladas— antes de llegar a María, como diciéndole al pueblo judío: si Dios pudo obrar a través de ellas para sostener el linaje del Mesías, también puede obrar a través de esta joven. El nombre Jesús (Yeshúa) significa "Dios es salvación", y anuncia la misión: el Antiguo Testamento ya prometía que en los días del Mesías Dios salvaría a su pueblo (Jeremías 23:5-6).', greek: [g('Jesús', 'Ἰησοῦς', 'Iēsoûs', 'forma griega de Yeshúa (ישוע): "el Señor salva"')] },
      { ref: '1:22-23', text: 'Todo esto aconteció para que se cumpliese lo dicho por el Señor por medio del profeta: "He aquí, una virgen concebirá y dará a luz un hijo, y llamarás su nombre Emanuel", que traducido es: Dios con nosotros.', commentary: 'Mateo conecta el nacimiento con la profecía de Isaías 7:14, escrita unos setecientos años antes. Jesús no viene de una historia "limpia" sino redimida, y su segundo nombre profético, Emanuel, resume el resto del evangelio: Dios ya no habla desde lejos, sino que viene a habitar en medio de su pueblo.', greek: [] },
      { ref: '1:24-25', text: 'Y despertando José del sueño, hizo como el ángel del Señor le había mandado, y recibió a su mujer... y no la conoció hasta que dio a luz a su hijo primogénito.', commentary: 'José se casa con María en obediencia inmediata. En esa cultura, terminados los siete días de la ceremonia matrimonial se esperaba que el matrimonio se consumara, e incluso se creía que los hombres debían casarse jóvenes para no caer en tentación. Aun así, José se abstiene de tener relaciones con María hasta el nacimiento de Jesús, viviendo ya juntos — su obediencia no es solo externa, sino profunda, costosa y silenciosa, sin que el texto registre una sola palabra propia suya.', greek: [] },
    ],
    reflection: '¿Qué historia "no prolija" de tu propia familia creés que Dios no puede usar?',
    context: { title: 'Genealogías, honor y gematría en el mundo bíblico', body: 'Una genealogía servía para demostrar origen, honor y herencia, no solo parentesco. En la numerología hebrea (gematría), cada letra tiene un valor numérico: el nombre David (דוד) suma exactamente 14, lo que refuerza la estructura de tres bloques de catorce generaciones que organiza Mateo 1 y subraya que Jesús es el Hijo de David por excelencia.' },
  },
  2: {
    title: 'El Rey perseguido',
    intro: 'Cuando comienza el capítulo 2, Jesús ya no es un recién nacido: María y José viven en una casa y el niño podría tener desde varios meses hasta casi dos años. Gobierna Herodes el Grande, un rey impuesto por Roma que sostenía su trono con violencia, manipulación y miedo — el contraste exacto con el Rey que acaba de nacer.',
    blocks: [
      { ref: '2:1-2', text: '...vinieron del oriente unos magos a Jerusalén, diciendo: ¿Dónde está el rey de los judíos, que ha nacido? Porque su estrella hemos visto en el oriente, y venimos a adorarle.', commentary: 'Belén era una aldea pequeña, sin relevancia política ni económica — no el lugar lógico para buscar a un rey, aunque sí la ciudad de David y el lugar profetizado por Miqueas. Los magos, gente "del oriente" (probablemente Persia o Babilonia), no eran reyes como dirá después la tradición, sino sabios y astrónomos con acceso a textos judíos desde el exilio siglos antes: una élite intelectual, no supersticiosos improvisados. Su llegada generó conmoción: no venían a adorar a Herodes, sino preguntando por otro rey, una amenaza directa en un reino sostenido por el miedo.', greek: [g('magos', 'μάγοι', 'magoi', 'sabios y astrólogos de oriente, no reyes; una élite intelectual formada en el estudio de los cielos y los textos antiguos')] },
      { ref: '2:2', text: '"...su estrella hemos visto en el oriente, y venimos a adorarle."', commentary: 'La "estrella" fue muy probablemente un fenómeno astronómico significativo: entre los años 7 y 6 a.C. se registró una triple conjunción de Júpiter y Saturno en la constelación de Piscis, un evento poco frecuente. Júpiter era considerado el planeta del rey, Saturno estaba asociado a Israel en varias tradiciones orientales, y Piscis se interpretaba como el fin de una era. La señal celestial no les dio una dirección exacta —por eso viajan primero a Jerusalén, no directo a Belén—, sino una confirmación; necesitaron además de las Escrituras (citadas por los sacerdotes) para llegar al lugar correcto. Dios usa tanto la creación como la Palabra para guiar a quienes lo buscan con sinceridad.', greek: [] },
      { ref: '2:3', text: 'Oyendo esto, el rey Herodes se turbó, y toda Jerusalén con él.', commentary: 'Herodes era idumeo, no de linaje davídico, y sostenía su trono por favor de Roma más que por legitimidad; vivía obsesionado con perder el poder, al punto de haber mandado matar a su propia esposa e hijos por miedo a conspiraciones. Que "toda Jerusalén" se turbe junto con él muestra cómo el miedo de un líder se contagia a todo un pueblo — el contraste exacto con el tipo de Rey que Jesús será: uno que gobierna desde la entrega y la cercanía, no desde el control.', greek: [] },
      { ref: '2:4-6', text: '"Y tú, Belén, de la tierra de Judá, no eres la más pequeña entre los príncipes de Judá; porque de ti saldrá un guiador, que apacentará a mi pueblo Israel."', commentary: 'Ante la noticia, Herodes no busca a Dios: convoca a los principales sacerdotes y escribas para preguntarles, fríamente, dónde debía nacer el Cristo. Ellos citan sin dudar la profecía de Miqueas 5:2, escrita unos setecientos años antes — no describe a un rey autoritario sino a un pastor que cuida y da la vida por su pueblo. La tensión del pasaje es notable: conocen exactamente la Escritura correcta, pueden citarla de memoria, pero ninguno se mueve hacia Belén.', greek: [] },
      { ref: '2:7-8', text: '"Id allá y averiguad con diligencia acerca del niño; y cuando le halléis, hacédmelo saber, para que yo también vaya y le adore."', commentary: 'Herodes llama a los magos en secreto y les pide un dato preciso —el momento exacto en que apareció la estrella— no por curiosidad espiritual sino para calcular la edad del niño y planear su eliminación. El lenguaje de "adorar" es una máscara piadosa: no toda persona que habla de Dios lo hace con el corazón sincero.', greek: [] },
      { ref: '2:9-10', text: 'Y he aquí la estrella que habían visto en el oriente iba delante de ellos, hasta que llegando, se detuvo sobre donde estaba el niño.', commentary: 'Una vez que los magos se alejan del palacio y del poder humano, la guía de Dios vuelve a hacerse visible con precisión. En el camino hacia Jesús hay dirección divina, no solo esfuerzo humano.', greek: [] },
      { ref: '2:11', text: '...y postrándose, lo adoraron; y abriendo sus tesoros, le ofrecieron presentes: oro, incienso y mirra.', commentary: 'Los magos no encuentran un palacio sino un niño pequeño en brazos de María, y aun así se postran y adoran antes de ofrecer nada. Los regalos no son simbólicos al azar: el oro reconoce realeza, el incienso —usado en el culto del templo— reconoce divinidad, y la mirra, usada para embalsamar cuerpos, anticipa que este Rey nació también para morir.', greek: [g('mirra', 'σμύρνα', 'smýrna', 'resina usada para embalsamar cuerpos; un regalo que anticipa la muerte de Jesús')] },
      { ref: '2:12', text: 'Pero siendo avisados por revelación en sueños que no volviesen a Herodes, regresaron a su tierra por otro camino.', commentary: 'Quien se encuentra verdaderamente con Jesús ya no puede colaborar, ni siquiera sin saberlo, con sistemas de muerte o poder corrupto. El detalle final es simbólico: vinieron por un camino, pero regresaron por otro — comenzaron el viaje guiados por una estrella y lo terminan guiados por la obediencia.', greek: [] },
      { ref: '2:13-15', text: '"Levántate y toma al niño y a su madre, y huye a Egipto..." ...para que se cumpliese lo que dijo el Señor por medio del profeta: De Egipto llamé a mi Hijo.', commentary: 'La advertencia ahora es para José, que no discute ni demora: se levanta de noche y huye. La cita de Oseas 11:1 se refería originalmente a Israel, liberado de la esclavitud egipcia; Mateo muestra que Jesús recorre el mismo camino que su pueblo, pero como el Hijo fiel — donde Israel fue infiel, él no lo será.', greek: [] },
      { ref: '2:16-18', text: '...y mató a todos los niños varones que había en Belén y en todos sus alrededores, de edad de dos años abajo... Voz fue oída en Ramá... Raquel que llora a sus hijos.', commentary: 'Al verse burlado por los magos, Herodes responde con violencia extrema — su poder se sostiene en el terror, no en la verdad. Mateo conecta el hecho con la profecía de Jeremías: el llanto de Raquel representa el dolor profundo de un pueblo herido, y ni siquiera esta brutalidad escapa al plan de Dios.', greek: [] },
      { ref: '2:19-23', text: '...vino a la tierra de Israel... y vino y habitó en la ciudad que se llama Nazaret... para que se cumpliese lo que fue dicho por los profetas, que había de ser llamado nazareno.', commentary: 'Con la muerte de Herodes —según las fuentes históricas, humillante y dolorosa— Dios vuelve a hablar y José obedece de nuevo. Al enterarse de que Arquelao, igual de cruel, reina en Judea, se dirige a Galilea y se establece en Nazaret: una aldea pequeña y sin prestigio, de la que después se dirá "¿de Nazaret puede salir algo bueno?". Mateo no cita una profecía puntual sino una idea presente en varios profetas: el Mesías sería despreciado y rechazado. El Rey prometido no se forma en palacios sino en el anonimato — el poder de Dios se perfecciona en lo pequeño y lo despreciado.', greek: [] },
    ],
    reflection: '¿En qué área buscás "ubicar" a Jesús para tu propia conveniencia, como Herodes con los magos, en vez de adorarlo de verdad?',
    context: { title: 'Herodes el Grande: un trono sostenido por el miedo', body: 'Idumeo y no descendiente de David, Herodes gobernaba por designación romana y sabía que su autoridad no estaba legitimada ante el pueblo judío. Vivió obsesionado con perder el poder, al punto de ordenar la muerte de esposas, hijos y parientes cercanos ante la mínima sospecha. Ese es el trasfondo exacto de su reacción ante la noticia de "el rey de los judíos".' },
  },
  3: {
    title: 'La voz que prepara el camino',
    intro: 'Han pasado unos treinta años desde el nacimiento de Jesús. Mateo salta directo al inicio del ministerio público, y después de casi 400 años sin profetas desde Malaquías, aparece Juan el Bautista en el desierto — no desde el templo ni el sistema religioso oficial, vestido como los antiguos profetas, con un mensaje directo: el reino de los cielos se ha acercado.',
    blocks: [
      { ref: '3:1', text: 'En aquellos días vino Juan el Bautista predicando en el desierto de Judea.', commentary: 'Juan era pariente de Jesús (tradicionalmente su primo), unos seis meses mayor, y su nacimiento fue milagroso: Zacarías y Elisabet eran de edad avanzada cuando el ángel Gabriel les anunció que tendrían un hijo. Aunque probablemente compartió momentos de infancia con Jesús, Juan no creció dentro del sistema religioso tradicional; con el tiempo se fue al desierto, el lugar de preparación, soledad y dependencia total de Dios, y es ahí donde comienza su ministerio — no en la ciudad, ni en el templo, ni en la comodidad.', greek: [] },
      { ref: '3:2', text: '"Arrepentíos, porque el reino de los cielos se ha acercado."', commentary: 'Metanoéo no describe solo culpa sino un cambio real de dirección, de mente y de corazón. El mensaje de Juan no es político ni busca popularidad: antes de que el Rey se manifieste, el corazón debe prepararse.', greek: [g('arrepentíos', 'μετανοέω', 'metanoéo', 'cambiar por completo de mente y dirección; no es solo sentir culpa sino girar el rumbo')] },
      { ref: '3:3', text: '"Voz del que clama en el desierto: Preparad el camino del Señor, enderezad sus sendas."', commentary: 'Mateo conecta a Juan directamente con la profecía de Isaías 40:3: lo que está pasando no es un evento aislado sino cumplimiento profético anunciado siglos antes. En la antigüedad, cuando un rey iba a visitar una ciudad se arreglaban los caminos para su llegada — la imagen es clara: el Rey viene, y el corazón debe ser preparado. Juan no es el Mesías; es la voz que prepara el camino.', greek: [] },
      { ref: '3:4', text: 'Y Juan estaba vestido de pelo de camello, y tenía un cinto de cuero alrededor de sus lomos; y su comida era langostas y miel silvestre.', commentary: 'La descripción no es casual: es muy similar a la del profeta Elías (2 Reyes 1:8), lo cual conecta con la profecía de Malaquías que anunciaba a alguien en el espíritu de Elías antes del Mesías. Su vestimenta identificaba su llamado profético y representaba austeridad; su comida, permitida por la ley, muestra una vida sencilla sostenida por lo que Dios proveía en el desierto. Juan predicaba cambio, pero primero él mismo vivía rendido — su vida era el mensaje antes que sus palabras.', greek: [] },
      { ref: '3:5-6', text: 'Entonces salía a él Jerusalén, y toda Judea, y toda la provincia de alrededor del Jordán, y eran bautizados por él en el Jordán, confesando sus pecados.', commentary: 'A pesar de su enorme impacto y popularidad, Juan nunca tomó un rol que no le correspondía ni permitió que la atención se desviara hacia él: tenía influencia, pero no ambición; autoridad, pero no ego. El bautismo que ofrecía no era solo un ritual externo sino una señal visible de arrepentimiento genuino, y su ministerio apuntaba siempre a Otro.', greek: [] },
      { ref: '3:7-9', text: '"¡Generación de víboras! ¿Quién os enseñó a huir de la ira venidera?... y no penséis decir dentro de vosotros mismos: A Abraham tenemos por padre."', commentary: 'Fariseos y saduceos, los grupos religiosos más influyentes de la época, conocían las Escrituras como nadie y cumplían cuidadosamente sus prácticas, pero Juan ve más allá de lo externo: tenían religión sin transformación, tradición sin un corazón rendido. Confiaban en su linaje étnico como si eso reemplazara el arrepentimiento — la herencia espiritual no basta si el corazón está lejos de Dios.', greek: [g('generación de víboras', 'γεννήματα ἐχιδνῶν', 'gennēmata echidnōn', 'expresión durísima; los acusa de portar el mismo veneno que dicen combatir')] },
      { ref: '3:10', text: '"Y ya también el hacha está puesta a la raíz de los árboles; por tanto, todo árbol que no da buen fruto es cortado y echado en el fuego."', commentary: 'Dios no busca apariencia religiosa sino fruto real. Sin arrepentimiento verdadero y sin un corazón transformado, incluso los más religiosos pueden estar lejos de Dios — el árbol sin fruto digno de arrepentimiento está en peligro, sin importar cuánto conocimiento tenga.', greek: [] },
      { ref: '3:11-12', text: '"...el que viene tras mí, es más poderoso que yo, cuyo calzado no soy digno de llevar... Su aventador está en su mano, y limpiará su era."', commentary: 'El pueblo esperaba un Mesías rey y guerrero que derrotara a Roma; el lenguaje de juicio de Juan —el hacha, el aventador, el fuego que limpia— encajaba con esa expectativa de justicia inmediata. Pero cuando Jesús comienza su ministerio no actúa como el rey guerrero imaginado: predica amor, perdón y misericordia. Más adelante (Mateo 11:2-3), incluso Juan, ya en la cárcel, enviará a preguntar si Jesús es realmente "el que había de venir" — la realidad no coincidía del todo con la expectativa, y Dios no siempre actúa como esperamos, aunque siempre actúa conforme a su propósito perfecto.', greek: [] },
      { ref: '3:13-15', text: '"Deja ahora, porque así conviene que cumplamos toda justicia."', commentary: 'Juan bautizaba para arrepentimiento, y Jesús no tenía pecado; por eso Juan intenta impedírselo. Pero Jesús se somete a lo que correspondía, no porque lo necesitara para sí mismo, sino para cumplir el plan de Dios y dar ejemplo: se identifica con la humanidad pecadora sin haber pecado, mostrando que su misión sería de cercanía y sustitución, no de superioridad distante. La obediencia no depende de necesidad personal, sino de alinearse con la voluntad de Dios.', greek: [] },
      { ref: '3:16-17', text: '...y he aquí los cielos le fueron abiertos, y vio al Espíritu de Dios que descendía como paloma... y una voz de los cielos, que decía: Este es mi Hijo amado, en quien tengo complacencia.', commentary: 'Antes de hacer un milagro, antes de predicar a las multitudes, antes de enfrentar la tentación, Jesús recibe la afirmación del Padre. Su identidad no se basa en lo que hace sino en quién es. El pasaje muestra además una manifestación clara de la Trinidad: el Hijo es bautizado, el Espíritu desciende, el Padre habla desde el cielo — el servicio correcto nace de una identidad ya segura en Dios.', greek: [g('complacencia', 'εὐδοκέω', 'eudokéo', 'aprobación plena y gozosa; no una tolerancia sino un deleite activo')] },
    ],
    reflection: '¿Dejás que tu identidad la defina lo que hacés, o la voz del Padre, como en el bautismo de Jesús?',
    context: { title: 'El bautismo de arrepentimiento de Juan', body: 'El bautismo de Juan en el río Jordán era un acto público de arrepentimiento, no solo un ritual externo: las personas confesaban su pecado y mostraban visiblemente un cambio interior. A pesar de su enorme popularidad, Juan nunca ocupó el lugar del Mesías — entendía con claridad que su misión era preparar el camino, no ocuparlo.' },
  },
  4: {
    title: 'Tentado en el desierto, llamado junto al lago',
    intro: 'Antes del ministerio público hubo formación privada. El mismo Espíritu que descendió sobre Jesús en el bautismo ahora lo conduce al desierto — no para destruirlo, sino para probar y afirmar una identidad que el enemigo intentará cuestionar tres veces.',
    blocks: [
      { ref: '4:1-4', text: '...si eres Hijo de Dios, di que estas piedras se conviertan en pan. Él respondió... Escrito está: No sólo de pan vivirá el hombre, sino de toda palabra que sale de la boca de Dios.', commentary: 'La tentación ataca primero la identidad misma —"si eres Hijo de Dios"— justo después de que el Padre la afirmara en el bautismo. Jesús no debate ni argumenta: responde con la Escritura aprendida y guardada de antemano.', greek: [g('tentado', 'πειράζω', 'peirázo', 'poner a prueba; no solo "tentar a pecar" sino examinar bajo presión')] },
      { ref: '4:8-10', text: '...todo esto te daré, si postrado me adorares. Entonces Jesús le dijo: Vete, Satanás... Al Señor tu Dios adorarás, y a él sólo servirás.', commentary: 'La tercera tentación ofrece el reino sin pasar por la cruz: la corona sin el sufrimiento, a cambio de un solo acto de adoración indebida. Jesús no negocia; reprende y responde otra vez con Deuteronomio.', greek: [g('servirás', 'λατρεύω', 'latreúo', 'rendir culto o servicio reservado exclusivamente a Dios')] },
      { ref: '4:18-20', text: '...Venid en pos de mí, y os haré pescadores de hombres. Ellos, dejando al instante las redes, le siguieron.', commentary: 'Jesús ve más allá de la apariencia: donde otros veían pescadores comunes, él veía instrumentos del Reino. La respuesta es inmediata, sin negociar garantías — así comienza el discipulado.', greek: [g('síganme', 'ἀκολουθέω', 'akolouthéo', 'seguir como discípulo, no simplemente caminar detrás de alguien')] },
    ],
    reflection: '¿Qué "piedra convertida en pan" te ofrece hoy un atajo para resolver una necesidad real por fuera de la obediencia a Dios?',
    context: { title: 'El número cuarenta y el desierto como lugar de prueba', body: 'Cuarenta días llovió en tiempos de Noé, cuarenta años Israel anduvo en el desierto, cuarenta días Moisés estuvo en el monte, cuarenta días caminó Elías hasta Horeb. En la Escritura, cuarenta es el número del trato de Dios antes de una nueva etapa — Jesús no comienza su ministerio público sin atravesar antes ese mismo proceso.' },
  },
  5: {
    title: 'El Sermón del Monte: las bienaventuranzas y la ley del corazón',
    intro: 'Después de la genealogía, el nacimiento, el bautismo y la victoria en el desierto, Jesús sube a un monte y se sienta: la postura del maestro que enseña con autoridad, evocando a Moisés en el Sinaí. Frente a multitudes de Galilea, Decápolis, Jerusalén, Judea y más allá del Jordán, dirige la enseñanza a los discípulos que ya lo siguen — no es evangelismo masivo, es formación.',
    blocks: [
      { ref: '5:1-2', text: 'Y viendo la multitud, subió al monte; y sentándose, vinieron a él sus discípulos.', commentary: 'Sentarse era la postura del maestro con autoridad. Frente a miles de personas hambrientas y expectantes, Jesús podría haber predicado algo cómodo —prosperidad, una ley diluida, gracia sin exigencia—. En cambio usa el momento de mayor audiencia de su ministerio para decir la verdad más costosa: cómo es realmente vivir en el Reino de Dios.', greek: [] },
      { ref: '5:3', text: '"Bienaventurados los pobres en espíritu, porque de ellos es el reino de los cielos."', commentary: 'Makarios no es una emoción pasajera sino un estado de plenitud independiente de las circunstancias, palabra que los griegos reservaban para sus dioses autosuficientes. Ptochós no es pobreza moderada sino indigencia total, sin nada propio de qué depender. Ser pobre en espíritu es pararse ante Dios y decir "no tengo nada, te necesito completamente" — lo opuesto a la mentalidad farisea que medía la espiritualidad por el mérito acumulado.', greek: [g('bienaventurados', 'μακάριος', 'makarios', 'plenitud profunda que no depende de las circunstancias externas'), g('pobres', 'πτωχός', 'ptochós', 'indigencia total; sin nada propio de lo que depender')] },
      { ref: '5:4', text: '"Bienaventurados los que lloran, porque ellos serán consolados."', commentary: 'Penthéo es el término más fuerte del griego para el duelo: el llanto por la muerte de un ser querido. Aplicado aquí, es el quebranto honesto por el pecado propio — algo que los fariseos cubrían con religiosidad en vez de sentir, pero que recorre a los profetas (Jeremías, Ezequiel, Nehemías, Daniel). La promesa usa parakaléo, de la misma raíz que "Parákletos" (el Espíritu Santo): no es solo alivio, es la presencia activa de Dios que se pone al lado de quien llora de verdad.', greek: [g('lloran', 'πενθέω', 'penthéo', 'duelo profundo y visible, el término más fuerte para el lamento'), g('consolados', 'παρακαλέω', 'parakaléo', 'ser acompañado y fortalecido por una presencia activa, de la misma raíz que "Parákletos"')] },
      { ref: '5:5', text: '"Bienaventurados los mansos, porque ellos heredarán la tierra."', commentary: 'Praus describía a un caballo de guerra domado: fuerza enorme puesta bajo control, no ausencia de fuerza. El manso puede ser corregido sin quebrarse y tiene poder para herir pero elige no hacerlo — como Jesús mismo (Mateo 11:29), manso con las personas pero decidido al volcar las mesas del templo. En la cultura romana la mansedumbre era virtud de esclavos; Jesús invierte esa jerarquía citando el Salmo 37:11.', greek: [g('mansos', 'πραΰς', 'praus', 'fuerza sometida bajo control, como un caballo de guerra domado')] },
      { ref: '5:6', text: '"Bienaventurados los que tienen hambre y sed de justicia, porque ellos serán saciados."', commentary: 'Peinao y dipsao describen el hambre y la sed de quien no comió ni bebió en días, no un apetito moderado. Dikaiosyne (justicia) tiene doble dimensión: ser recto delante de Dios y anhelar que lo torcido del mundo sea enderezado. La promesa usa chortazo, saciar como a un animal que comió hasta quedar completamente satisfecho — no es premio al que ya llegó, sino promesa al que no puede dejar de buscar.', greek: [g('hambre', 'πεινάω', 'peinao', 'hambre extrema, no un apetito moderado'), g('justicia', 'δικαιοσύνη', 'dikaiosyne', 'ser recto delante de Dios y anhelar que las cosas sean como él quiere, también en lo social'), g('saciados', 'χορτάζω', 'chortazo', 'quedar completamente satisfecho, como un animal que comió hasta no desear más')] },
      { ref: '5:7', text: '"Bienaventurados los misericordiosos, porque ellos alcanzarán misericordia."', commentary: 'Eleemon no es sentimiento pasivo sino compasión que se mueve por dentro ante el dolor ajeno y actúa en consecuencia. Es la única bienaventuranza con reciprocidad directa: el corazón que se cierra ante la necesidad del otro termina cerrándose también ante la gracia de Dios, como desarrollará la parábola del siervo perdonado que no perdona (Mateo 18:23-35).', greek: [g('misericordiosos', 'ἐλεήμων', 'eleemon', 'compasión que se conmueve por dentro y se traduce en acción, no solo lástima')] },
      { ref: '5:8', text: '"Bienaventurados los de limpio corazón, porque ellos verán a Dios."', commentary: 'Katharos describía el oro sin aleación, el grano sin paja: pureza sin doble fondo, sin distancia entre lo que se muestra y lo que se es. Chocaba con la religiosidad farisea, experta en pureza externa mientras el corazón podía estar contaminado (5:11 lo desarrollará). El corazón se limpia guardando la Palabra (Salmo 119:9) y con vigilancia activa (Proverbios 4:23) — y la promesa es la más íntima de todas: ver a Dios mismo.', greek: [g('limpio', 'καθαρός', 'katharos', 'puro, sin mezcla ni doble fondo — lo que se ve es exactamente lo que hay')] },
      { ref: '5:9', text: '"Bienaventurados los pacificadores, porque ellos serán llamados hijos de Dios."', commentary: 'Eirenopoios no es quien evita el conflicto sino quien activamente construye eirene — equivalente griego del hebreo shalom, plenitud e integridad restaurada, no mera ausencia de guerra. El verdadero pacificador entra en el conflicto para sanarlo. La promesa es de identidad: ser reconocido como hijo de Dios, el gran Pacificador que tomó la iniciativa de reconciliar al mundo consigo (2 Corintios 5:19).', greek: [g('pacificadores', 'εἰρηνοποιός', 'eirenopoios', 'el que activamente construye la paz (eirene/shalom), no solo el que la evita o la desea')] },
      { ref: '5:10', text: '"Bienaventurados los que padecen persecución por causa de la justicia, porque de ellos es el reino de los cielos."', commentary: 'Dioko describe hostilidad activa y sostenida, como un cazador tras su presa — no incomodidad leve. En la mentalidad de la época la prosperidad era señal de bendición y la persecución de maldición; Jesús invierte esa lógica. La promesa repite la de la primera bienaventuranza: el Reino abre y cierra la lista, para el que empieza en humildad y para el que persiste bajo presión.', greek: [g('persecución', 'διώκω', 'dioko', 'hostilidad activa y sostenida, como un cazador que persigue a su presa')] },
      { ref: '5:11', text: '"Bienaventurados sois cuando por mi causa os vituperen y os persigan, y digan toda clase de mal contra vosotros, mintiendo."', commentary: 'Jesús pasa de la tercera a la segunda persona y agrega algo nuevo: "por mi causa", equiparando su persona con la justicia de Dios. Tres palabras progresivas describen el ataque: oneidizo (avergonzar públicamente), dioko (perseguir) y pseudomai (calumniar con mentiras fabricadas). Es la misma línea de los profetas insultados y perseguidos por ser fieles — la persecución personal por Jesús no es fracaso espiritual sino identificación profunda con él.', greek: [g('vituperen', 'ὀνειδίζω', 'oneidizo', 'avergonzar públicamente, atacar la reputación y el honor de alguien'), g('mintiendo', 'ψεύδομαι', 'pseudomai', 'calumnias, mentiras fabricadas intencionalmente para destruir')] },
      { ref: '5:12', text: '"Alegraos y regocijaos, porque vuestro galardón es grande en los cielos; porque así persiguieron a los profetas que fueron antes de vosotros."', commentary: 'Chairo es gozo interior y estable (de la misma raíz que "gracia"); agalliao es júbilo desbordante, casi incontenible. El misthos (recompensa) es polys, grande, como el salario justo de un trabajador. Al conectar la persecución de los discípulos con la de los profetas, Jesús normaliza el rechazo y a la vez los ubica en la misma línea de Elías, Jeremías e Isaías: no es mala noticia, es herencia.', greek: [g('regocijaos', 'ἀγαλλιάω', 'agalliao', 'júbilo desbordante, casi incontrolable, que necesita expresarse hacia afuera'), g('galardón', 'μισθός', 'misthos', 'recompensa concreta, como el salario que un trabajador recibe por su labor')] },
      { ref: '5:13', text: '"Vosotros sois la sal de la tierra; pero si la sal se desvaneciere, ¿con qué será salada?"', commentary: 'La sal preservaba de la corrupción, realzaba el sabor y se usaba en las ofrendas (Levítico 2:13) — ser sal es las tres cosas a la vez. Moraino ("perder el sabor") comparte raíz con la palabra griega para "necio": la sal insípida no es solo inútil, es una contradicción consigo misma. No se pierde de golpe sino por tibieza progresiva, al mezclarse tanto con el entorno que deja de distinguirse.', greek: [g('desvaneciere', 'μωραίνω', 'moraino', 'volverse insípido y necio; comparte raíz con la palabra griega para "necio"')] },
      { ref: '5:14-15', text: '"Vosotros sois la luz del mundo; una ciudad asentada sobre un monte no se puede esconder. Ni se enciende una luz y se pone debajo de un almud."', commentary: 'A diferencia de la sal, que actúa desde adentro de manera invisible, la luz (phos) actúa desde afuera de manera visible. La lámpara se ponía sobre el lychnia (candelero) para iluminar toda la casa, nunca bajo el modios (medida de granos) — imagen casi absurda de esconder deliberadamente lo que se encendió para alumbrar.', greek: [g('almud', 'μόδιος', 'modios', 'vasija de medida usada en el comercio de granos; esconder la lámpara debajo es una imagen absurda a propósito')] },
      { ref: '5:16', text: '"Así alumbre vuestra luz delante de los hombres, para que vean vuestras buenas obras, y glorifiquen a vuestro Padre que está en los cielos."', commentary: 'La luz no apunta hacia quien la porta sino hacia Dios: doxazo significa reconocer y proclamar su valor y grandeza. Las buenas obras no son estrategia de imagen sino consecuencia natural de una vida transformada — el mismo patrón de todas las bienaventuranzas, que nunca buscan el protagonismo propio.', greek: [g('glorifiquen', 'δοξάζω', 'doxazo', 'reconocer y proclamar el valor y la grandeza de alguien')] },
      { ref: '5:17', text: '"No penséis que he venido para abrogar la ley o los profetas; no he venido para abrogar, sino para cumplir."', commentary: 'Jesús anticipa la sospecha de que viene a destruir la Ley y la niega, pero al mismo tiempo eleva su estándar: cuanto más se entiende la profundidad real de la Ley, más evidente se vuelve que nadie puede alcanzarla solo. Pleroo no es simplemente obedecer sino llenar hasta el borde, llevar a su plenitud — la Ley apuntaba siempre a un corazón transformado (Jeremías 31:33, Ezequiel 36:26-27), no solo a la conducta externa.', greek: [g('cumplir', 'πληρόω', 'pleroo', 'llenar hasta el borde, completar, llevar a su plenitud máxima')] },
      { ref: '5:18', text: '"Ni una jota ni una tilde pasará de la ley, hasta que todo se haya cumplido."', commentary: 'Iota era la letra más pequeña del alfabeto hebreo y keraia el pequeño trazo que distinguía letras similares: hasta el detalle más mínimo de la Ley tiene peso. Los rabinos habían contado 613 mandamientos —248 positivos y 365 negativos—, desde lo aparentemente alcanzable ("no matarás") hasta lo humanamente imposible de cumplir en plenitud ("amarás... con todo tu corazón"). Santiago 2:10 y Gálatas 3:10 son categóricos: fallar en un solo punto es quebrantarla toda. La Ley es espejo, no escalera: muestra lo que somos, no nos eleva a lo que deberíamos ser.', greek: [g('jota', 'ἰῶτα', 'iota', 'la letra más pequeña del alfabeto hebreo, apenas un trazo')] },
      { ref: '5:19', text: '"De manera que cualquiera que quebrante uno de estos mandamientos muy pequeños, y así enseñe a los hombres, muy pequeño será llamado en el reino de los cielos."', commentary: 'Hay responsabilidad adicional para quien enseña, no solo para quien practica: la coherencia entre lo que se enseña y lo que se vive no es opcional. Es una advertencia directa a los líderes religiosos presentes, y un principio permanente — "no os hagáis maestros muchos" (Santiago 3:1).', greek: [] },
      { ref: '5:20', text: '"Si vuestra justicia no fuere mayor que la de los escribas y de los fariseos, no entraréis en el reino de los cielos."', commentary: 'Perisseuo significa abundar, exceder con creces — no una mejora marginal sino una justicia de naturaleza distinta. La de los fariseos era externa y medible; la del Reino nace de un corazón transformado. La paradoja: la única forma de superarla no es esforzarse más sino reconocer, como el pobre en espíritu, que no se puede solo (Filipenses 3:9).', greek: [g('mayor', 'περισσεύω', 'perisseuo', 'abundar, desbordar, exceder con creces — no una mejora marginal')] },
      { ref: '5:21', text: '"Oísteis que fue dicho a los antiguos: No matarás; y cualquiera que matare será culpable de juicio."', commentary: 'El mandamiento más conocido de todos, uno que cualquiera en la audiencia sentía tener cubierto sin esfuerzo — y por eso mismo generaba una falsa seguridad: mientras no cruzaras la línea visible, estabas bien delante de Dios.', greek: [] },
      { ref: '5:22', text: '"Pero yo os digo que cualquiera que se enoje contra su hermano, será culpable de juicio... y cualquiera que le dijere: Insensato, quedará expuesto al infierno de fuego."', commentary: 'Orgizo no es la reacción del primer segundo sino la ira que se elige mantener y alimentar. Jesús traza una progresión —enojo interno, insulto, maldición— y las pone bajo el mismo peso moral que el asesinato: "todo aquel que odia a su hermano es homicida" (1 Juan 3:15). El asesinato no empieza con un arma; empieza en el corazón.', greek: [g('enoje', 'ὀργίζω', 'orgizo', 'ira que se elige mantener y alimentar, no la reacción momentánea')] },
      { ref: '5:23-24', text: '"Si traes tu ofrenda al altar, y allí te acuerdas de que tu hermano tiene algo contra ti... ve, reconcíliate primero con tu hermano, y entonces ven y presenta tu ofrenda."', commentary: 'No se puede adorar genuinamente mientras hay una relación rota — un ritual religioso no tapa ni compensa eso. Notablemente Jesús habla del caso en que uno mismo causó el daño: no hay que esperar a que el otro venga, hay que tomar la iniciativa.', greek: [] },
      { ref: '5:25-26', text: '"Ponte de acuerdo con tu adversario pronto, entre tanto que estás con él en el camino... de cierto te digo que no saldrás de allí, hasta que pagues el último cuadrante."', commentary: 'El camino al tribunal es una oportunidad de oro que se pierde una vez que el juez toma el caso. Kodrantes era la moneda más pequeña del sistema romano: nada quedará sin rendir cuentas. Cuanto más se espera para reconciliarse, más caro sale.', greek: [g('cuadrante', 'κοδράντης', 'kodrantés', 'la moneda más pequeña del sistema monetario romano')] },
      { ref: '5:27', text: '"Oísteis que fue dicho: No cometerás adulterio."', commentary: 'Otro mandamiento que la mayoría sentía tener cubierto: una violación grave y visible, castigada incluso con la muerte en la ley judía. Esa tranquilidad está a punto de romperse.', greek: [] },
      { ref: '5:28', text: '"Pero yo os digo que cualquiera que mira a una mujer para codiciarla, ya adulteró con ella en su corazón."', commentary: 'Epithumeo describe un deseo intenso y deliberado, la mirada que se entretiene y se alimenta, no el primer vistazo involuntario. Si el adulterio ocurre en el corazón sin contacto físico, el problema no está principalmente en el cuerpo sino en lo que se permite entrar y quedarse en la mente — hoy, tan accesible como una pantalla.', greek: [g('codiciarla', 'ἐπιθυμέω', 'epithumeo', 'deseo intenso y deliberado; la mirada que se entretiene y se alimenta, no el primer vistazo')] },
      { ref: '5:29-30', text: '"Si tu ojo derecho te es ocasión de caer, sácalo, y échalo de ti... y si tu mano derecha te es ocasión de caer, córtala, y échala de ti."', commentary: 'Hipérbole deliberada, no instrucción literal de automutilación: ningún sacrificio es demasiado grande para proteger el corazón del pecado. Geenna (el Valle de Hinom, donde se quemaba basura de forma permanente) es la imagen del infierno real que Jesús menciona con más frecuencia que cualquier otro tema, precisamente porque le importa que nadie llegue ahí.', greek: [g('infierno', 'γέεννα', 'geenna', 'el Valle de Hinom, a las afueras de Jerusalén, donde se quemaba basura permanentemente — imagen del juicio final')] },
      { ref: '5:31', text: '"También fue dicho: Cualquiera que repudiare a su mujer, dele carta de divorcio."', commentary: 'Referencia a Deuteronomio 24:1. La escuela del rabino Hillel había llegado a permitir el divorcio por motivos tan triviales como que la esposa quemara la comida — un certificado pensado para proteger a la mujer se había vuelto herramienta de descarte fácil.', greek: [] },
      { ref: '5:32', text: '"Pero yo os digo que el que repudia a su mujer, a no ser por causa de fornicación, hace que ella adultere."', commentary: 'Porneia (infidelidad sexual grave) es la única excepción que Jesús reconoce, no una puerta abierta a cualquier motivo. Una mujer divorciada en el siglo I quedaba en posición extremadamente vulnerable, casi obligada a volver a casarse para sobrevivir — el divorcio fácil era también una sentencia social. En Mateo 19:4-6 Jesús apelará al diseño original en Génesis: "lo que Dios ha unido, que no lo separe el hombre".', greek: [g('fornicación', 'πορνεία', 'porneia', 'infidelidad sexual grave; la única excepción que Jesús reconoce para el divorcio')] },
      { ref: '5:33', text: '"Otra vez habéis oído que fue dicho a los antiguos: No perjurarás, sino cumplirás al Señor tus juramentos."', commentary: 'La Ley no prohibía jurar, prohibía jurar en falso (Levítico 19:12, Números 30:2). Con el tiempo los rabinos desarrollaron una jerarquía de fórmulas de juramento con distinto peso, y jurar se volvió una manera de hablar con énfasis sin comprometerse del todo.', greek: [] },
      { ref: '5:34-36', text: '"Pero yo os digo: No juréis en ninguna manera; ni por el cielo, porque es el trono de Dios; ni por la tierra, porque es el estrado de sus pies..."', commentary: 'Jesús desmonta cada fórmula con el mismo argumento: nadie tiene control real sobre aquello por lo que jura, ni siquiera sobre el color de su propio cabello. Omnuo (jurar) se había vuelto un hábito verbal vacío, desconectado de responsabilidad real.', greek: [g('juréis', 'ὀμνύω', 'omnuo', 'invocar algo superior como garantía formal de la propia palabra')] },
      { ref: '5:37', text: '"Pero sea vuestro hablar: Sí, sí; no, no; porque lo que es más de esto, de mal procede."', commentary: 'En griego, nai nai, ou ou: que la palabra alcance por sí sola, sin necesitar nada externo que la respalde. Si hace falta jurar para que te crean, el problema no está en la fórmula sino en el carácter — el ciudadano del Reino no necesita juramentos porque su vida entera es coherente.', greek: [] },
      { ref: '5:38', text: '"Oísteis que fue dicho: Ojo por ojo, y diente por diente."', commentary: 'La ley del talión (Éxodo 21:24, Levítico 24:20) no nació para fomentar la venganza sino para limitarla: la respuesta debía ser proporcional, no mayor. Con el tiempo se convirtió en justificación personal para devolver el golpe.', greek: [] },
      { ref: '5:39', text: '"Mas yo os digo: No resistáis al que es malo; antes, a cualquiera que te hiera en la mejilla derecha, vuélvele también la otra."', commentary: 'No es pasividad ante la injusticia sino rechazo a la lógica de la venganza. Un revés en la mejilla derecha era el insulto más humillante de la cultura del siglo I; poner la otra no es debilidad sino un acto consciente de poder: "tu desprecio no me define ni me controla" — la misma fuerza sometida de praus (5:5).', greek: [] },
      { ref: '5:40', text: '"Y al que quiera ponerte a pleito y quitarte la túnica, déjale también la capa."', commentary: 'La capa era el bien más básico que alguien poseía, tan esencial que la Ley prohibía retenerla de noche como garantía (Éxodo 22:26-27). Dar más de lo que se pide no es resignación: expone la avaricia del que demanda más que cualquier pelea legal.', greek: [] },
      { ref: '5:41', text: '"Y a cualquiera que te obligue a llevar carga por una milla, ve con él dos."', commentary: 'Los soldados romanos podían obligar legalmente a cualquiera a cargar su equipo por una milla romana —así fue forzado Simón de Cirene con la cruz de Jesús—. Caminar la segunda milla, no exigida, es del que ya no va obligado sino libre.', greek: [] },
      { ref: '5:42', text: '"Al que te pida, dale; y al que quiera tomar de ti prestado, no se lo rehúses."', commentary: 'Generosidad sin cálculo, sin evaluar primero si el otro lo merece. Nace de haber recibido una gracia que tampoco se mereció — el hilo de todo el pasaje: alguien que ya no vive a la defensiva, que puede dar sin perder porque su seguridad no depende de lo que retiene.', greek: [] },
      { ref: '5:43', text: '"Oísteis que fue dicho: Amarás a tu prójimo, y aborrecerás a tu enemigo."', commentary: '"Aborrecerás a tu enemigo" no está en el Antiguo Testamento — es una conclusión cultural, reforzada por grupos como los esenios y por el patriotismo judío bajo dominio romano, no Escritura.', greek: [] },
      { ref: '5:44', text: '"Pero yo os digo: Amad a vuestros enemigos, bendecid a los que os maldicen... y orad por los que os ultrajan y os persiguen."', commentary: 'Agapao es el amor más alto del griego bíblico: no eros ni philia, sino un amor que decide y se sostiene sin depender de lo que el otro hace. Orar por quien te persigue es de los actos más difíciles que existen, porque es casi imposible sostener el odio hacia alguien por quien genuinamente se ora.', greek: [g('amad', 'ἀγαπάω', 'agapao', 'amor que decide y se sostiene independientemente de lo que el otro hace o devuelve')] },
      { ref: '5:45', text: '"Para que seáis hijos de vuestro Padre que está en los cielos, que hace salir su sol sobre malos y buenos, y que hace llover sobre justos e injustos."', commentary: 'Amar al enemigo no es idealismo sino imitación directa del carácter de Dios, cuyo sol y lluvia no son selectivos. Ser "hijo" en el siglo I significaba parecerse al padre en carácter, no solo llevar su apellido.', greek: [] },
      { ref: '5:46-47', text: '"Porque si amáis a los que os aman, ¿qué recompensa tendréis? ¿No hacen también lo mismo los publicanos?"', commentary: 'Amar solo a quienes te aman no distingue al discípulo de nadie — hasta los recaudadores de impuestos, los más despreciados socialmente, hacen eso mismo. La pregunta queda abierta y sin salida: ¿qué hacés de más?', greek: [] },
      { ref: '5:48', text: '"Sed, pues, vosotros perfectos, como vuestro Padre que está en los cielos es perfecto."', commentary: 'Teleios no es perfección moral sin defectos sino completo, maduro, que alcanzó su propósito. El modelo no es un profeta ni un ángel sino el Padre mismo — un estándar tan alto que nadie puede alcanzarlo solo, lo cual devuelve al capítulo a su propio comienzo: makarios el pobre en espíritu, el que reconoce que no puede y necesita completamente a Dios.', greek: [g('perfectos', 'τέλειος', 'téleios', 'completo, maduro; que alcanzó plenamente el propósito para el que fue hecho')] },
    ],
    reflection: 'De las nueve bienaventuranzas y las seis antítesis de este capítulo, ¿cuál te confronta hoy con más fuerza — no la que más te gusta explicar, sino la que menos querés vivir?',
    context: { title: 'La Halajá y los 613 mandamientos', body: 'La Torá no era solo un código de reglas: era el pacto de Dios con su pueblo, su identidad y su honor. Con el tiempo, escribas y fariseos desarrollaron la Halajá, una tradición oral que buscaba "cercar" la Ley para no violarla en ningún detalle, y llegaron a contar 613 mandamientos (248 positivos, 365 negativos). Algunos eran alcanzables ("no matarás"), otros ya apuntaban al corazón ("no codiciarás"), y otros —"amarás a tu prójimo como a ti mismo", "amarás al Señor tu Dios con todo tu corazón"— eran, en plenitud, humanamente imposibles. Santiago 2:10 y Gálatas 3:10 son categóricos: fallar en un solo punto era quebrantarla toda. El problema no era amar la Ley; era que, sin darse cuenta, la obediencia se había vuelto externa y performativa, y la Ley —diseñada para mostrar la necesidad de un Salvador, no para producirlo— se convirtió en un sistema de apariencias.' },
  },
  6: {
    title: 'Piedad secreta y el tesoro del corazón',
    intro: 'Jesús acaba de hablar de amar al enemigo y de ser perfectos como el Padre. Ahora baja a algo más cotidiano pero igual de profundo: no solo qué hacemos, sino para quién lo hacemos. Limosna, oración y ayuno —las tres prácticas centrales de la piedad judía— se examinan bajo la misma pregunta, y el capítulo cierra con una advertencia sobre dónde ponemos el corazón: en el tesoro que se acumula o en el Padre que ya sabe lo que necesitamos.',
    blocks: [
      { ref: '6:1', text: 'Cuídense de no hacer sus obras de justicia delante de la gente para ser vistos por ellos. Si actúan así, su Padre que está en el cielo no les dará ninguna recompensa.', commentary: 'Jesús no habla de gente maliciosa que calcula su maldad, sino de algo más sutil: el corazón que necesita público para encontrar valor en lo que hace. En el siglo I la piedad visible era parte del honor social, así que el problema no es hacer el bien sino hacerlo para que te vean — cuando la mirada ajena se convierte en el motor, Dios deja de ser el destinatario.', greek: [g('vistos', 'θεαθῆναι', 'theathênai', 'ser visto como en un espectáculo; de la misma raíz que "teatro"')] },
      { ref: '6:2-4', text: 'Cuando des limosna, no toques trompeta delante de ti, como hacen los hipócritas en las sinagogas y en las calles, para ser alabados por los hombres... no sepa tu izquierda lo que hace tu derecha.', commentary: 'En el templo había recipientes de ofrenda con forma de trompeta (shofrot) cuyo sonido delataba el tamaño de la moneda; algunos entienden la frase literalmente, otros como metáfora, pero la imagen era vívida: dar de una manera que no pase desapercibida. "Hipócritas" designaba en el mundo griego a los actores de teatro, alguien que usa una máscara distinta de su vida real. La imagen de la mano izquierda que no sabe lo que hace la derecha es la hipérbole más directa posible: la generosidad debe ser tan natural que ni uno mismo se detenga a registrarla.', greek: [g('hipócritas', 'ὑποκριταί', 'hypokritai', 'actores de teatro; alguien que usa una máscara para representar un papel distinto de su vida real')] },
      { ref: '6:5-6', text: 'Cuando ores, no seas como los hipócritas... mas tú, cuando ores, entra en tu cuarto, y cerrada la puerta, ora a tu Padre que está en secreto.', commentary: 'Los judíos piadosos oraban tres veces al día —horas que coincidían con los sacrificios del templo— y esos momentos podían sorprenderlos en la calle o el mercado, la tentación exacta de convertir la oración en demostración. El "cuarto" era probablemente el tameion, la habitación interior sin ventanas donde se guardaban provisiones, el lugar más apartado de la casa: retiro total, sin público. Jesús mismo buscaba ese espacio, madrugando o retirándose a lugares desiertos.', greek: [g('cuarto', 'ταμεῖον', 'tameion', 'habitación interior sin ventanas, el lugar más apartado de la casa')] },
      { ref: '6:7-8', text: 'Y orando, no uséis vanas repeticiones, como los gentiles, que piensan que por su palabrería serán oídos. No os hagáis, pues, semejantes a ellos, porque vuestro Padre sabe de qué cosas tenéis necesidad, antes que vosotros le pidáis.', commentary: 'Las religiones del mundo mediterráneo usaban la repetición para forzar la respuesta de sus dioses —desde los sacerdotes de Baal clamando durante horas hasta las fórmulas mágicas de los papiros del período—, como si la intensidad obligara a actuar a un dios distraído. Jesús corta esa lógica: el Padre ya sabe lo que necesitás antes de pedirlo, así que la oración no es un sistema para informar a Dios sino una relación para estar con él.', greek: [g('vanas repeticiones', 'βατταλογέω', 'battalogéo', 'balbuceo vacío; palabras multiplicadas sin sentido, desconectadas de cualquier intención real')] },
      { ref: '6:9-13', text: 'Padre nuestro que estás en los cielos, santificado sea tu nombre. Venga tu reino. Hágase tu voluntad... Danos hoy nuestro pan cotidiano. Y perdónanos nuestras deudas, como también nosotros perdonamos... y no nos metas en tentación, mas líbranos del mal.', commentary: 'A diferencia del Amidá o el Kadish —oraciones largas y estructuradas que los judíos devotos recitaban de memoria—, el Padre Nuestro es breve y tiene cinco movimientos: reconocer con quién se habla (llamar a Dios "Abba" era una cercanía casi inaudita), poner primero la agenda de Dios antes que la propia, pedir el pan de hoy como dependencia diaria, atar el perdón recibido al perdón dado, y reconocer la necesidad de protección espiritual. Es una oración más orientada a Dios y a los demás que a uno mismo: "perdónanos" es plural.', greek: [g('Padre', 'Ἀββά', 'Abba', 'término íntimo y de confianza que un hijo pequeño usaba con su papá')] },
      { ref: '6:14-15', text: 'Porque si perdonáis a los hombres sus ofensas, os perdonará también a vosotros vuestro Padre celestial; mas si no perdonáis a los hombres sus ofensas, tampoco vuestro Padre os perdonará vuestras ofensas.', commentary: 'De todos los elementos del Padre Nuestro, el perdón es el único al que Jesús le da seguimiento inmediato. No es una lógica transaccional sino de coherencia: el que de verdad recibió perdón no puede cerrar el puño ante el que le debe. Si lo cierra, muestra que no entendió lo que recibió — la misma idea que Jesús desarrollará con toda su fuerza en la parábola del siervo de Mateo 18.', greek: [] },
      { ref: '6:16-18', text: 'Cuando ayunéis, no seáis austeros, como los hipócritas... para no manifestar a los hombres que ayunas, sino a tu Padre que está en secreto; y tu Padre que ve en lo secreto te recompensará en público.', commentary: 'El único ayuno obligatorio en la Ley era el del Día de la Expiación, pero los fariseos ayunaban también lunes y jueves, desaliñando el cabello y cubriéndose de ceniza — el ayuno convertido en gestión de la reputación espiritual. Moisés, David, Ester y Nehemías ayunaron en momentos de crisis genuina, no como ritual programado; el ayuno somete el cuerpo para liberar el espíritu, y por eso Jesús pide lavarse la cara: si nadie sabe que ayunaste, el ayuno fue real.', greek: [] },
      { ref: '6:19-21', text: 'No os hagáis tesoros en la tierra, donde la polilla y el orín corrompen... sino haceos tesoros en el cielo... porque donde esté vuestro tesoro, allí estará también vuestro corazón.', commentary: 'Jesús no condena el trabajo ni la prosperidad, sino acumular como fin en sí mismo: todo lo que se guarda acá tiene fecha de vencimiento. La frase final invierte la lógica esperada — no es que el corazón defina el tesoro, sino que el tesoro (adónde va el dinero) es lo que termina llevándose el corazón detrás.', greek: [] },
      { ref: '6:22-23', text: 'La lámpara del cuerpo es el ojo; así que, si tu ojo es bueno, todo tu cuerpo estará lleno de luz... pero si tu ojo es maligno, todo tu cuerpo estará en tinieblas.', commentary: 'En la cultura hebrea, un "ojo bueno" describía a alguien generoso y de corazón abierto, y un "ojo malo" a alguien tacaño y cerrado — no es casual que Jesús use esta imagen en medio de la enseñanza sobre el dinero. La manera en que miramos los recursos colorea todo lo demás: la avaricia disfrazada de prudencia es una oscuridad que ni siquiera se reconoce a sí misma como tal.', greek: [] },
      { ref: '6:24', text: 'Ninguno puede servir a dos señores; porque o aborrecerá al uno y amará al otro, o estimará al uno y menospreciará al otro. No podéis servir a Dios y a las riquezas.', commentary: 'Jesús no dice que sea difícil servir a los dos: dice que es imposible. El lenguaje que usa —amar, aborrecer, estimar, menospreciar— son palabras de relación, no de contabilidad: pone al dinero en el mismo nivel que a Dios en su capacidad de exigir el corazón humano por completo.', greek: [g('riquezas', 'μαμωνᾶς', 'mamonas', 'término arameo que personifica las riquezas casi como una entidad con voluntad propia')] },
      { ref: '6:25-27', text: 'Por tanto os digo: No os afanéis por vuestra vida, qué habéis de comer... ¿Quién de vosotros podrá, por mucho que se afane, añadir a su estatura un codo?', commentary: 'El "por tanto" conecta directo con lo anterior: si Dios es tu señor, la preocupación pierde su razón de ser, porque afanarse es actuar como si Dios no fuera suficiente. Jesús no responde con filosofía sino con una pregunta práctica —la preocupación no agrega ni una hora de vida— y con una observación concreta: las aves no siembran ni cosechan, y el Padre las alimenta.', greek: [g('os afanéis', 'μεριμνάω', 'merimnáo', 'una mente dividida entre el presente y el futuro imaginado, incapaz de estar en un solo lugar')] },
      { ref: '6:28-30', text: 'Mirad los lirios del campo, cómo crecen; no trabajan ni hilan; mas os digo, que ni aun Salomón con toda su gloria se vistió así como uno de ellos.', commentary: 'Salomón fue el rey más rico de la historia de Israel, con un trono de marfil cubierto de oro; y Jesús dice que un lirio silvestre lo supera en esplendor. La comparación es teológica, no estética: si Dios invierte tanto en una flor que dura un día, "gente de poca fe" no es un insulto sino un diagnóstico — no del temperamento ansioso, sino de cuánto se cree realmente que Dios es quien dice ser.', greek: [] },
      { ref: '6:31-33', text: 'No os afanéis, pues, diciendo: ¿Qué comeremos...? Porque los gentiles buscan todas estas cosas... Mas buscad primeramente el reino de Dios y su justicia, y todas estas cosas os serán añadidas.', commentary: 'Correr detrás de la seguridad material como motor principal de la vida es, dice Jesús, lo que hace quien no conoce a Dios como Padre — vivir como huérfano que debe conseguir todo por sí mismo. El reordenamiento es claro: cuando el Reino ocupa el primer lugar, todo lo demás encuentra su lugar también, no como magia sino como principio de orden.', greek: [] },
      { ref: '6:34', text: 'Así que, no os afanéis por el día de mañana, porque el día de mañana traerá su afán. Basta a cada día su propio mal.', commentary: 'Jesús no promete que nada va a salir mal; dice algo más concreto: cargar el peso del mañana además del de hoy multiplica el sufrimiento sin necesidad. El maná del desierto era diario —el que guardaba de más lo encontraba podrido— porque Dios diseñó una provisión que pide confianza renovada cada día, no un contrato cerrado de una sola vez.', greek: [] },
    ],
    reflection: '¿Hay algo en tu vida espiritual —dar, orar, ayunar— que hacés más pensando en quién te ve que en Dios mismo?',
    context: { title: 'Las oraciones fijas del judaísmo del siglo I', body: 'Los fariseos tenían el Amidá o Shemoné Esré ("las Dieciocho Bendiciones"), una oración larga y estructurada recitada de pie tres veces al día, y el Kadish, una doxología que glorificaba el nombre de Dios en momentos específicos de la liturgia. Eran oraciones hermosas y teológicamente ricas, pero con el tiempo muchos las recitaban de memoria sin estar presentes en ninguna de sus palabras — el peligro exacto que Jesús señala antes de enseñar el Padre Nuestro, deliberadamente breve.' },
  },
  7: {
    title: 'Juzgar, pedir y edificar sobre la roca',
    intro: 'Jesús cierra el Sermón del Monte con una serie de instrucciones prácticas para la vida en comunidad: cómo mirar los errores propios antes que los ajenos, la promesa de un Padre que responde a quien le pide, la regla de oro, y una advertencia final sobre la diferencia entre escuchar y obedecer.',
    blocks: [
      { ref: '7:1-2', text: 'No juzguéis, para que no seáis juzgados. Porque con el juicio con que juzgáis, seréis juzgados, y con la medida con que medís, os será medido.', commentary: 'El griego krino no describe simple opinión o evaluación, sino posicionarse como autoridad final sobre el valor o la condición de otra persona — dictar veredicto sobre su corazón, cosa distinta del discernimiento necesario y bíblico. La lógica de reciprocidad recorre todo el sermón: la misma medida que usás se usa con vos.', greek: [g('juzguéis', 'κρίνω', 'krino', 'posicionarse como autoridad final sobre el valor o la condición de otra persona, no discernimiento')] },
      { ref: '7:3-5', text: '¿Y por qué miras la paja que está en el ojo de tu hermano, y no echas de ver la viga que está en tu propio ojo?... y entonces verás bien para sacar la paja del ojo de tu hermano.', commentary: 'Jesús era un maestro de la exageración deliberada: alguien caminando con una viga entera en el ojo mientras intenta sacarle una partícula al otro es absurdo a propósito. El problema no es ayudar a los demás —el objetivo final del pasaje es justamente poder hacerlo con claridad— sino intentarlo sin haberse revisado primero: la viga propia distorsiona la visión antes de que se pueda ver bien la astilla ajena.', greek: [] },
      { ref: '7:6', text: 'No deis lo santo a los perros, ni echéis vuestras perlas delante de los cerdos, no sea que las pisoteen con sus patas, y vuelvan y os despedacen.', commentary: 'Perros y cerdos eran animales ritualmente impuros en la cultura judía, y aquí señalan contextos que rechazan y destruyen activamente lo sagrado. El discernimiento que el versículo anterior prohíbe es condenar a una persona; el que este versículo permite es evaluar cuándo y cómo compartir lo valioso — no juzgar el corazón de alguien y a la vez reconocer que cierta conversación, en ese momento, no va a llevar a ningún lado.', greek: [] },
      { ref: '7:7-11', text: 'Pedid, y se os dará; buscad, y hallaréis; llamad, y se os abrirá... ¿Qué hombre hay de vosotros, que si su hijo le pide pan, le dará una piedra?', commentary: 'Las tres palabras griegas están en presente continuo: pedir, buscar, llamar como posturas sostenidas, no actos de una sola vez. El argumento final es de menor a mayor: si hasta los padres humanos imperfectos saben no hacerle daño a un hijo que pide, ¿cuánto más va a dar el Padre perfecto lo que sus hijos necesitan?', greek: [g('pedid', 'αἰτέω', 'aiteo', 'pedir de forma continua y sostenida'), g('buscad', 'ζητέω', 'zeteo', 'buscar activamente, sin abandonar'), g('llamad', 'κρούω', 'krouo', 'llamar a la puerta de forma persistente')] },
      { ref: '7:12', text: 'Así que, todo lo que queráis que los hombres hagan con vosotros, así también haced vosotros con ellos; porque esto es la ley y los profetas.', commentary: 'La versión negativa de esta regla —no hagas lo que no querés que te hagan— aparece en la filosofía griega, el judaísmo rabínico y Confucio; es un principio de abstención. La versión de Jesús es positiva y activa: no alcanza con no dañar, hay que actuar bien. Es un llamado a la iniciativa, no solo a la contención.', greek: [] },
      { ref: '7:13-14', text: 'Entrad por la puerta estrecha; porque ancha es la puerta, y espacioso el camino que lleva a la perdición... porque estrecha es la puerta, y angosto el camino que lleva a la vida, y pocos son los que la hallan.', commentary: 'El camino ancho no exige nada, y por eso es el que elige la mayoría; el angosto incomoda y exige transformación. La puerta estrecha no es arbitrariamente pequeña: tiene una forma específica, la forma de Jesús, y hay que moldearse a ella para pasar — el orgullo y la doble vida simplemente no entran.', greek: [] },
      { ref: '7:15-20', text: 'Guardaos de los falsos profetas, que vienen a vosotros con vestidos de ovejas, pero por dentro son lobos rapaces. Por sus frutos los conoceréis.', commentary: 'Un profeta hablaba de parte de Dios, no principalmente predecía el futuro; un falso profeta pretendía esa autoridad sin tenerla, y Deuteronomio 18 daba dos criterios: si la profecía no se cumple, o si lleva a adorar otros dioses, es falsa — el éxito visible o los milagros no bastaban para distinguirlo. El único criterio que da Jesús es el fruto: cómo trata a su familia, cómo maneja el dinero, si genera dependencia o madurez en quienes lo rodean.', greek: [] },
      { ref: '7:19', text: 'Todo árbol que no da buen fruto, es cortado y echado en el fuego.', commentary: 'El versículo no habla solo del que hace el mal activamente, sino del que simplemente no produce nada — la ausencia de fruto no es neutralidad, es problema. La misma lógica de la parábola del siervo que enterró su talento en Mateo 25: no lo malgastó ni lo robó, y aun así fue suficiente para la condena.', greek: [] },
      { ref: '7:21-23', text: 'No todo el que me dice: Señor, Señor, entrará en el reino de los cielos... y entonces les declararé: Nunca os conocí; apartaos de mí, hacedores de maldad.', commentary: 'Jesús no habla de gente en pecado abierto, sino de personas que profetizaron, expulsaron demonios e hicieron milagros en su nombre — señales que en cualquier contexto religioso pasarían por evidencia de una relación con Dios. "Jamás los conocí" no es una relación perdida sino una que nunca existió: el milagro en sí mismo no prueba origen divino, porque incluso el poder contrario puede falsificar señales; el criterio real es el fruto, no la experiencia.', greek: [] },
      { ref: '7:24-27', text: 'Cualquiera, pues, que me oye estas palabras, y las hace, le compararé a un hombre prudente, que edificó su casa sobre la roca... y descendió lluvia, y vinieron ríos, y soplaron vientos, y azotaron aquella casa; y no cayó, porque estaba fundada sobre la roca.', commentary: 'Jesús no contrasta al que escucha con el que no escucha, sino a dos personas que escuchan el mismo sermón: la diferencia no es de información sino de aplicación. Las tormentas llegan para los dos por igual; el cimiento no evita la prueba, determina cómo se sale de ella.', greek: [] },
      { ref: '7:28-29', text: 'Y cuando terminó Jesús estas palabras, las gentes se admiraban de su doctrina; porque les enseñaba como quien tiene autoridad, y no como los escribas.', commentary: 'Los maestros de la Ley enseñaban citando tradiciones de otros rabinos; Jesús decía "yo os digo" en primera persona, doce veces en el sermón, sin apelar a ninguna autoridad prestada. Esa autoridad no venía de interpretar mejor un texto ajeno, sino de ser él mismo la Palabra — la pregunta que deja abierta el sermón entero no es cuánto se entendió, sino si se escuchó y se puso en práctica, o se escuchó y se siguió igual.', greek: [g('autoridad', 'ἐξουσία', 'exousía', 'autoridad legítima y reconocida, no derivada de citar a otros maestros')] },
    ],
    reflection: '¿Estás construyendo tu vida sobre la roca (escuchar y practicar) o sobre la arena (escuchar y admirar sin cambiar nada)?',
    context: { title: 'Profetas y falsos profetas en la tradición bíblica', body: 'Deuteronomio 18:20-22 daba dos criterios para reconocer a un falso profeta: si su profecía no se cumplía, o si llevaba al pueblo a adorar a otros dioses, era falso — incluso si hacía milagros o convencía a muchos. El Nuevo Testamento confirma que un poder contrario puede falsificar señales sobrenaturales (2 Tesalonicenses 2:9, Apocalipsis 13:13-14, Éxodo 7:11), por lo que el criterio final nunca es el milagro sino el fruto: la vida transformada, no la experiencia espectacular.' },
  },
  8: {
    title: 'Autoridad sobre la enfermedad, la naturaleza y los demonios',
    intro: 'Tras el Sermón del Monte, una multitud enorme y creciente —Mateo usa una expresión griega más intensa que antes, ochloi polloi— sigue a Jesús montaña abajo. Lo que viene ahora es esa misma autoridad puesta en acción: cruzando, una tras otra, las fronteras más infranqueables del mundo del siglo I. La social con un leproso, la étnica con un centurión romano, la doméstica en la casa de Pedro, la natural en una tormenta y la espiritual en territorio gentil.',
    blocks: [
      { ref: '8:2-4', text: '"Señor, si quieres, puedes limpiarme." ... "Quiero; sé limpio." Y al instante su lepra desapareció.', commentary: 'El leproso se acerca en medio de una multitud que debería huir de él, y lo primero que hace es postrarse: en el griego original, proskuneo, el mismo verbo usado para adorar a Dios. No negocia ni reclama nada; dice "si quieres" dejando la voluntad abierta, sin poner en duda el poder. Jesús responde tocándolo —contacto físico impensable con un leproso, que contaminaba ritualmente a quien lo tocara— y lo envía al sacerdote: no viene a demoler el sistema de la Ley sino a cumplirlo desde adentro, reintegrando al hombre a su comunidad.', greek: [g('se postró', 'προσκυνέω', 'proskynéō', 'postrarse en adoración; el mismo verbo usado para adorar a Dios')] },
      { ref: '8:5-9', text: '"Señor, mi criado yace en casa paralítico, gravemente atormentado." ... "Señor, no soy digno de que entres bajo mi techo; solamente di la palabra..."', commentary: 'Un centurión romano —representante visible de la ocupación, alguien con quien un rabino judío no tenía obligación de tratar— se acerca a interceder por su siervo, algo inusual en una cultura donde los siervos eran propiedad. Su argumento nace de su propia experiencia militar: así como sus órdenes se ejecutan sin que él esté presente, entiende que la autoridad de Jesús no depende de la cercanía física. No necesita que Jesús toque ni vea al enfermo; alcanza con la palabra.', greek: [] },
      { ref: '8:10-13', text: '"De cierto os digo, que ni aun en Israel he hallado tanta fe." ... "Ve, y como creíste, te sea hecho." Y su criado fue sanado en aquella misma hora.', commentary: 'Es una de las pocas veces en los evangelios en que Jesús se asombra, y no es por una señal sino por la fe de un soldado pagano. Lo que dice después debió sacudir a la audiencia judía: el banquete del Reino no está reservado para los que nacieron adentro del sistema religioso, sino que vendrán de oriente y occidente, mientras "los hijos del reino" pueden quedar afuera por no reconocer al Mesías que tienen delante. La sanidad ocurre sin que Jesús toque, vea ni esté presente: solo la palabra.', greek: [] },
      { ref: '8:14-15', text: 'Vio a la suegra de Pedro postrada en cama, con fiebre. Y tocó su mano, y la fiebre la dejó; y ella se levantó, y les servía.', commentary: 'Un milagro doméstico y sencillo, sin pedido previo ni confesión de fe: Jesús ve la necesidad y actúa. La respuesta de la mujer es inmediata —se levanta a servir, sin pausa ni celebración— y establece un patrón que se repite en todo el capítulo: la sanidad de Jesús produce servicio, no solo alivio.', greek: [] },
      { ref: '8:16-17', text: 'Y echó fuera a los espíritus con la palabra, y sanó a todos los enfermos; para que se cumpliese lo dicho por el profeta Isaías: Él mismo tomó nuestras enfermedades, y llevó nuestras dolencias.', commentary: 'Al caer la tarde, la casa de Pedro se llena de endemoniados y enfermos, y Jesús los sana a todos, no solo a los que tenían más fe. Mateo conecta esto directamente con Isaías 53, el capítulo del Siervo sufriente: el milagro no es espectáculo, es cumplimiento profético hecho carne.', greek: [] },
      { ref: '8:18-20', text: '"Maestro, te seguiré adondequiera que vayas." ... "Las zorras tienen guaridas, y las aves del cielo nidos; mas el Hijo del Hombre no tiene dónde recostar la cabeza."', commentary: 'En medio de la ola de milagros y entusiasmo, Jesús decide moverse; no se queda donde la fama crece. Un escriba se ofrece a seguirlo a cualquier parte, y Jesús no lo rechaza pero tampoco lo romantiza: le aclara de entrada que no hay comodidad ni estabilidad garantizada en el camino.', greek: [] },
      { ref: '8:21-22', text: '"Señor, permíteme que vaya primero y entierre a mi padre." ... "Sígueme, y deja que los muertos entierren a sus muertos."', commentary: 'La frase suena dura sin contexto cultural: en el judaísmo del siglo I, enterrar al padre era la obligación filial más sagrada, por encima incluso del estudio de la Torá. Jesús no está siendo insensible al duelo; está señalando que el llamado a seguirlo tiene una urgencia que no espera, ni siquiera detrás del deber más sagrado conocido en esa cultura.', greek: [] },
      { ref: '8:23-26', text: 'Y se levantó una tempestad tan grande que las olas cubrían la barca; pero él dormía. ... "¿Por qué teméis, hombres de poca fe?" Entonces, levantándose, reprendió a los vientos y al mar; y se hizo grande bonanza.', commentary: 'Jesús está con ellos en la barca y duerme en medio de una tormenta conocida por ser repentina y letal en ese lago —varios de los discípulos eran pescadores de esas mismas aguas y sabían que el peligro era real. Llamarlos "hombres de poca fe" no niega que hayan hecho lo correcto al ir a despertarlo: fueron a la persona indicada. Pero su fe todavía no llegaba a descansar en que su sola presencia ya era garantía suficiente, con tormenta o sin ella.', greek: [] },
      { ref: '8:27', text: '"¿Qué hombre es este, que aun los vientos y el mar le obedecen?"', commentary: 'Ya lo habían visto sanar leprosos, centuriones y endemoniados, y aun así la pregunta emerge genuina. Los milagros sobre enfermedades podían atribuirse a un gran profeta; pero los vientos y el mar no le obedecen a ningún profeta. Mateo deja la pregunta flotando sin responderla todavía: es la pregunta central de todo el evangelio.', greek: [] },
      { ref: '8:28-29', text: '"¿Qué tienes con nosotros, Jesús, Hijo de Dios? ¿Has venido acá para atormentarnos antes de tiempo?"', commentary: 'Ya en territorio gentil, dos endemoniados que vivían entre los sepulcros reconocen a Jesús de inmediato, sin cuestionar su autoridad ni preguntar quién es: la única duda que expresan es el tiempo, no la sentencia. Es una ironía profunda que el mundo espiritual reconozca a Jesús con más claridad que buena parte de los seres humanos a lo largo del evangelio.', greek: [] },
      { ref: '8:30-32', text: '"Si nos echas, permítenos ir a aquel hato de cerdos." Él les dijo: "Id." ... todo el hato se precipitó en el mar por un despeñadero, y perecieron en las aguas.', commentary: 'Los demonios piden ser redirigidos, no simplemente echados: son territoriales, prefieren habitar animales impuros antes que la nada. Los cerdos, una vez poseídos, se destruyen a sí mismos — no porque Jesús lo ordene, sino porque lo demoníaco no construye ni sostiene nada; consume y destruye.', greek: [] },
      { ref: '8:33-34', text: 'Y toda la ciudad salió a encontrar a Jesús; y cuando le vieron, le rogaron que se fuera de sus contornos.', commentary: 'Acaban de ver a dos hombres aterradores completamente restaurados, y le piden a Jesús que se vaya. Probablemente por miedo al costo: perdieron una manada entera, una pérdida económica real, y temen lo que más podría costarles su presencia. Es una de las escenas más honestas del evangelio sobre la condición humana: no todos reciben con gratitud el poder de Dios cuando lo ven actuar.', greek: [] },
    ],
    reflection: 'Ante el poder de Dios actuando cerca tuyo, ¿reaccionás con el asombro agradecido del centurión o con el miedo al costo del pueblo de Gadara?',
    context: { title: 'La lepra y la exclusión ritual en el siglo I', body: 'Levítico 13-14 establecía el protocolo con precisión: el sacerdote examinaba al afectado, lo declaraba tamé (ritualmente impuro), y desde ese momento la persona quedaba excluida de la comunidad, obligada a vivir fuera del campamento, con ropa rasgada y el deber de gritar "¡Impuro!" al acercarse a alguien. No era solo enfermedad: era vergüenza pública obligatoria y exclusión permanente, y muchos la interpretaban como señal de maldición divina.' },
  },
  9: {
    title: 'Autoridad para perdonar y una mesa inesperada',
    intro: 'Mateo 9 continúa el ritmo del capítulo anterior —Jesús en movimiento constante, actuando con autoridad— pero la tensión con los fariseos se intensifica: ya no observan desde lejos, empiezan a confrontar directamente. Y el capítulo muestra algo que el 8 solo insinuó: Jesús no separa el cuerpo del alma como compartimentos distintos. Sana, perdona, restaura e incluye como acciones que brotan de la misma fuente.',
    blocks: [
      { ref: '9:1-2', text: 'Y le trajeron un paralítico, tendido sobre una cama; y al ver Jesús la fe de ellos, dijo al paralítico: "Ten ánimo, hijo; tus pecados te son perdonados."', commentary: 'Mateo destaca no la parálisis sino quiénes lo traen: sus amigos, que hacen el esfuerzo que él no puede hacer solo. Jesús ve la fe de ellos, no solo la del paralítico — la fe de la comunidad puede operar donde la fe individual está agotada. Y en vez de sanarlo primero, lo perdona primero: la parálisis era el problema visible, pero el pecado era el problema estructural.', greek: [] },
      { ref: '9:3-4', text: 'Y he aquí, algunos de los escribas decían dentro de sí: "Este blasfema." Y conociendo Jesús sus pensamientos...', commentary: 'Los escribas tienen una razón teológica precisa: en el judaísmo del siglo I, perdonar pecados era prerrogativa exclusiva de Dios, ni siquiera profetas o ángeles podían otorgarlo. La lógica es binaria: o Jesús es Dios, o es un blasfemo. Lo que no calculan es que él conoce sus pensamientos no pronunciados, algo que solo Dios puede hacer (Salmo 139:2).', greek: [] },
      { ref: '9:5-7', text: '"¿Qué es más fácil, decir: Los pecados te son perdonados, o decir: Levántate y anda? Pues para que sepáis que el Hijo del Hombre tiene potestad en la tierra para perdonar pecados..." Entonces se levantó, y se fue a su casa.', commentary: 'La pregunta invierte la lógica esperada: decir que los pecados están perdonados parece fácil porque nadie puede comprobarlo, pero en términos de autoridad requerida es infinitamente más difícil que sanar un cuerpo. El milagro visible es la firma que certifica el milagro invisible. Jesús no perdona en nombre de Dios como los profetas; perdona con autoridad propia.', greek: [g('potestad', 'ἐξουσία', 'exousía', 'autoridad legítima y reconocida, no solo poder o capacidad')] },
      { ref: '9:8', text: 'Y la gente, al verlo, se maravilló, y glorificó a Dios, que había dado tal potestad a los hombres.', commentary: 'La multitud todavía no termina de entender del todo quién es Jesús, pero el asombro los mueve en la dirección correcta: hacia el reconocimiento de que algo mayor que cualquier profeta está actuando en medio de ellos.', greek: [] },
      { ref: '9:9', text: '"Sígueme." Y se levantó, y le siguió.', commentary: 'Jesús ve a Mateo en su puesto de recaudación —traidor a ojos de los judíos, instrumento descartable a ojos de Roma, un hombre sin lugar en ningún lado— y le dice solo dos palabras. La respuesta es inmediata, sin negociar ni pedir garantías, en paralelo directo con el llamado de los primeros discípulos en el capítulo 4.', greek: [] },
      { ref: '9:10-13', text: '"¿Por qué come vuestro Maestro con los publicanos y pecadores?" ... "Los sanos no tienen necesidad de médico, sino los enfermos... Misericordia quiero, y no sacrificio."', commentary: 'La casa de Mateo se llena de recaudadores y "pecadores" comiendo con Jesús: la inclusión genuina de uno genera inclusión para otros, no como estrategia sino como consecuencia. Ante la pregunta de los fariseos —que no se animan a confrontarlo directamente—, Jesús cita Oseas 6:6: un sistema que protege la santidad evitando el contacto con el pecado no es la santidad del Reino; es asepsia religiosa.', greek: [] },
      { ref: '9:14-15', text: '"¿Por qué nosotros y los fariseos ayunamos muchas veces, y tus discípulos no ayunan?" ... "¿Acaso pueden los que están de bodas tener luto entre tanto que el esposo está con ellos? mas vendrán días cuando el esposo les será quitado, y entonces ayunarán."', commentary: 'La respuesta de Jesús tiene una lógica casi cotidiana: tienen al novio al lado, la persona con autoridad sobre la muerte y la enfermedad caminando junto a ellos, así que no es momento de luto. La mención de que "el esposo les será quitado" es una de las primeras alusiones veladas a su propia muerte en el evangelio.', greek: [] },
      { ref: '9:16-17', text: 'Nadie pone remiendo de paño nuevo en vestido viejo... Ni echan vino nuevo en odres viejos... sino echan el vino nuevo en odres nuevos, y lo uno y lo otro se conservan juntamente.', commentary: 'Las dos imágenes apuntan a lo mismo: lo que Jesús trae no es una reforma del sistema religioso existente, no es judaísmo mejorado. Es algo cualitativamente nuevo que requiere recipientes nuevos — una tensión permanente en la historia de la iglesia, no solo del siglo I.', greek: [] },
      { ref: '9:18-19', text: '"Mi hija acaba de morir; mas ven y pon tu mano sobre ella, y vivirá." Y se levantó Jesús, y le siguió con sus discípulos.', commentary: 'Jairo, dirigente de sinagoga, llega arrodillado: un hombre con posición religiosa y autoridad comunal, humillado por la muerte de su hija. No pide oración ni explicaciones teológicas; pide la presencia y el toque de Jesús, una fe que excede las categorías que el judaísmo del siglo I tenía disponibles.', greek: [] },
      { ref: '9:20-22', text: 'Una mujer enferma de flujo de sangre desde hacía doce años... tocó el borde de su manto... "Ten ánimo, hija; tu fe te ha salvado." Y la mujer fue salva desde aquella hora.', commentary: 'Doce años de hemorragia significaban doce años de impureza ritual permanente según Levítico 15: una exclusión silenciosa y continua, sin poder tocar a nadie sin contaminarlo. Tocar a Jesús era técnicamente una transgresión, pero repite el patrón del capítulo 8: lo que en otros produce contaminación, en contacto con él produce lo contrario. Jesús la llama "hija", la reconoce en vez de avergonzarla.', greek: [] },
      { ref: '9:23-26', text: '"Apartaos, porque la niña no está muerta, sino duerme." Y se burlaban de él. ... la tomó de la mano, y la niña se levantó.', commentary: 'En la casa de Jairo, entre flautistas y plañideras profesionales del duelo ritual, la respuesta a las palabras de Jesús es risa, no escepticismo respetuoso. El lenguaje de "dormida" no es un eufemismo: es una reconfiguración teológica de lo que significa morir, el mismo lenguaje que Pablo usará después en 1 Tesalonicenses 4 para los creyentes que murieron.', greek: [] },
      { ref: '9:27-31', text: '"Ten misericordia de nosotros, Hijo de David." ... "Conforme a vuestra fe os sea hecho." Y los ojos de ellos fueron abiertos.', commentary: 'El título "Hijo de David" está cargado de significado mesiánico: no piden solo sanidad, reconocen su linaje real. La frase "conforme a vuestra fe" no es una fórmula que convierte deseos en realidades, sino un principio más profundo: la fe es la postura del corazón que se alinea con la voluntad de Dios y se abre a recibir lo que él ya quiere dar.', greek: [] },
      { ref: '9:32-34', text: 'Le trajeron un mudo, endemoniado. Y echado fuera el demonio, el mudo habló... Pero los fariseos decían: "Por el príncipe de los demonios echa fuera los demonios."', commentary: 'La mudez no era una condición física sino el resultado de la opresión demoníaca. La multitud queda atónita; los fariseos, en cambio, prefieren atribuirle a Jesús un pacto con Satanás antes que reconocer la obra de Dios delante de sus ojos — no es ignorancia, es resistencia activa.', greek: [] },
      { ref: '9:35-38', text: 'Al ver las multitudes, tuvo compasión de ellas; porque estaban desamparadas y dispersas como ovejas que no tienen pastor... "Rogad, pues, al Señor de la mies, que envíe obreros a su mies."', commentary: 'La palabra griega para "compasión" describe una conmoción que viene desde las entrañas, no lástima observada desde la distancia. La imagen es precisa: ovejas sin pastor, no ovejas sin comida — la necesidad más profunda de la multitud era espiritual. Y la primera respuesta que Jesús pide no es acción sino oración: reconocer que la cosecha es del Señor antes de salir a trabajarla.', greek: [g('compasión', 'σπλαγχνίζομαι', 'splanchnízomai', 'conmoción visceral, dolor sentido desde las entrañas; no lástima observada desde lejos')] },
    ],
    reflection: 'Como el paralítico, ¿hay algo en tu vida donde necesitás que Jesús trate primero la causa (el pecado) antes que el síntoma visible?',
    context: { title: 'El perdón de pecados como prerrogativa exclusiva de Dios', body: 'En la tradición judía del siglo I, perdonar pecados no era algo que un profeta, un sacerdote o un ángel pudiera otorgar por cuenta propia: era prerrogativa exclusiva de Dios. Por eso, cuando Jesús le dice al paralítico "tus pecados te son perdonados", los escribas no tienen una tercera opción cómoda para interpretarlo: o es Dios mismo, o está blasfemando al usurpar algo que no le pertenece.' },
  },
  10: {
    title: 'El envío de los doce',
    intro: 'Jesús acaba de recorrer todos los pueblos y aldeas, vio a la multitud agobiada y desamparada como ovejas sin pastor, y declaró que la cosecha es abundante pero los obreros son pocos. Mateo 10 es el segundo gran bloque de enseñanza del evangelio, y el primero que no está dirigido a la multitud sino exclusivamente a los discípulos: un manual de instrucciones para el discipulado en misión que sigue hablando a cualquiera que decida seguir a Jesús con seriedad.',
    blocks: [
      { ref: '10:1', text: '"Reunió a sus doce discípulos y les dio autoridad para expulsar a los espíritus malignos y sanar toda enfermedad y toda dolencia."', commentary: 'Jesús no les da consejos ni les explica técnicas: les transfiere autoridad concreta, la misma que caracterizó su propio ministerio en los capítulos 8 y 9. Esa delegación no terminó con los doce — Juan 14:12 extiende la misma promesa a cualquiera que viva en relación real con él.', greek: [] },
      { ref: '10:2-4', text: '"Estos son los nombres de los doce apóstoles: primero Simón, llamado Pedro..."', commentary: 'Mateo lista a los doce: Simón Pedro, Andrés, Santiago y Juan (hijos de Zebedeo), Felipe, Bartolomé, el propio Mateo, Tomás, Santiago hijo de Alfeo, Tadeo, Simón el Zelote y Judas Iscariote. Cada uno representa algo de la diversidad que el Reino incluye — hasta un zelote que quería derrocar a Roma por la fuerza comparte equipo con el recaudador de impuestos que colaboraba con ella. Que Jesús los eligiera a ellos, ordinarios y contradictorios entre sí, muestra que el Reino no busca la élite religiosa: busca a los disponibles. Ver el perfil de cada uno en Personajes.', greek: [] },
      { ref: '10:5-7', text: '"No vayan entre los gentiles ni entren en ningún pueblo de los samaritanos. Vayan más bien a las ovejas perdidas del pueblo de Israel... El reino de los cielos está cerca."', commentary: 'La restricción a Israel es estratégica y temporal, no teológica: el mismo Jesús ya sanó al siervo del centurión romano y sanará a la hija de la mujer cananea. El plan redentor de Dios tiene un orden — de Israel hacia las naciones, como el propio Jesús formulará después de la resurrección en 28:19.', greek: [] },
      { ref: '10:8', text: '"Sanen a los enfermos, resuciten a los muertos, limpien a los que tienen lepra, expulsen a los demonios. Lo que ustedes recibieron gratis, dénlo gratis."', commentary: 'El evangelio del Reino no es solo proclamación verbal sino demostración de poder. Y la frase final resume la ética de todo ministerio genuino: nadie de los doce se ganó lo que Jesús les dio, y precisamente por eso no pueden convertirlo en mercancía ni en palanca de poder sobre otros.', greek: [] },
      { ref: '10:9-10', text: '"No lleven oro, ni plata, ni cobre en el cinturón; ni bolsa para el camino, ni dos túnicas, ni sandalia de repuesto, ni bastón; porque el trabajador merece su sustento."', commentary: 'Salir sin provisiones propias exige una dependencia radical de Dios, que provee a través de quienes reciben a los enviados. Es también la base de un principio que el Nuevo Testamento desarrollará extensamente: el que trabaja en la obra de Dios tiene derecho a ser sostenido por quienes se benefician de ella (1 Corintios 9:7-14).', greek: [] },
      { ref: '10:11-13', text: '"En cualquier pueblo o aldea donde entren... digan: \'Paz a esta casa.\' Si el hogar se lo merece, que la paz de ustedes reine en él; si no, que la paz se vuelva a ustedes."', commentary: 'El shalom hebreo detrás de "paz" describe plenitud y bienestar total, no solo un saludo cultural. Que la paz "regrese" si es rechazada revela algo importante: la paz que viene de Dios es estable y portátil — no se pierde ni se contamina por el ambiente donde es rechazada.', greek: [] },
      { ref: '10:14-15', text: '"Si alguno no los recibe... sacúdanse el polvo de los pies. Les aseguro que en el día del juicio será más tolerable el castigo para Sodoma y Gomorra que para ese pueblo."', commentary: 'Sacudirse el polvo invierte un gesto judío de separación de lo impuro: ahora es el pueblo que rechaza el mensaje el que queda marcado, no el que lo lleva. La comparación con Sodoma y Gomorra introduce un principio central del capítulo: la responsabilidad es proporcional al conocimiento recibido.', greek: [] },
      { ref: '10:16', text: '"Los envío como ovejas en medio de lobos. Sean astutos como serpientes y sencillos como palomas."', commentary: 'Tres imágenes definen la postura del discípulo en misión: la oveja sin protección propia frente al lobo, la serpiente que en la cultura del Antiguo Testamento simbolizaba sabiduría y lectura precisa del entorno, y la paloma como símbolo de pureza sin dobles intenciones. El discípulo maduro es estratégico pero transparente — consciente del peligro real, sin volverse deshonesto por eso.', greek: [] },
      { ref: '10:17-18', text: '"Tengan cuidado con la gente; los entregarán a los tribunales y los azotarán en las sinagogas. Por mi causa los llevarán ante gobernadores y reyes para dar testimonio a ellos y a los gentiles."', commentary: 'Jesús no endulza lo que viene: anuncia el costo antes de que ocurra, y llama la atención que parte de la persecución vendrá de las propias sinagogas, la comunidad religiosa de origen. Y sin embargo encuentra ahí una oportunidad — la persecución que busca silenciarlos los lleva exactamente a donde el evangelio necesita llegar.', greek: [] },
      { ref: '10:19-20', text: '"Cuando los arresten, no se preocupen por lo que van a decir... el Espíritu de su Padre hablará por medio de ustedes."', commentary: 'La promesa es específica de momentos de arresto y persecución, no una excusa para la improvisación en el ministerio ordinario. El Espíritu Santo no reemplaza la formación: la completa exactamente en los momentos donde la preparación humana tiene un límite.', greek: [] },
      { ref: '10:21-23', text: '"El hermano entregará a la muerte al hermano, y el padre al hijo... el que se mantenga firme hasta el fin será salvo."', commentary: 'Lo que Jesús describe no es una posibilidad remota: en contextos religiosos cerrados sigue ocurriendo literalmente hoy, y aun en contextos moderados la fe genuina genera tensiones familiares reales cuando alguien rompe con tradiciones profundamente arraigadas. El versículo 23 admite lecturas distintas sobre el "venir" del Hijo del Hombre, pero comunica con claridad la urgencia: hay trabajo que hacer y el tiempo es limitado.', greek: [] },
      { ref: '10:24-25', text: '"El discípulo no es superior a su maestro... Si al jefe de la casa lo han llamado Beelzebú, ¿cuánto más a los de su familia?"', commentary: 'Si a Jesús lo llamaron por el nombre del príncipe de los demonios, el discípulo puede esperar un trato similar. Pero el punto es más profundo que la advertencia: la meta del discípulo no es superar al maestro sino parecerse a él — la dirección correcta no es hacia arriba en posición sino hacia adentro en transformación.', greek: [] },
      { ref: '10:26-27', text: '"No hay nada encubierto que no llegue a revelarse... Lo que se les susurra al oído, proclámenlo desde las azoteas."', commentary: 'Hay dos capas en este pasaje: todo lo que se trama en la oscuridad contra el evangelio tiene fecha de vencimiento, y lo que se recibe en la intimidad del discipulado no está hecho para quedarse guardado. El conocimiento de Dios no es propiedad privada de quien lo recibe; es un depósito para ser distribuido.', greek: [] },
      { ref: '10:28-31', text: '"No teman a los que matan el cuerpo pero no pueden matar el alma... ustedes valen más que muchos gorriones."', commentary: 'Jesús reordena la jerarquía del miedo: el que puede quitar la vida física no puede tocar lo que realmente somos. Dos gorriones se vendían por la moneda más baja del sistema romano, y aun así ninguno cae a tierra sin que el Padre lo permita — el mismo Padre que tiene contados los cabellos de la cabeza de cada uno de ustedes.', greek: [] },
      { ref: '10:32-33', text: '"A cualquiera que me reconozca delante de los demás, yo también lo reconoceré delante de mi Padre... al que me niegue delante de los demás, yo también lo negaré."', commentary: 'El verbo griego para "reconocer" no describe solo creer en privado sino declarar públicamente. La promesa que acompaña esa confesión es extraordinaria: hay una intercesión activa de Jesús vinculada al testimonio público, no como sistema de méritos sino como consecuencia de una identificación mutua.', greek: [g('reconozca', 'ὁμολογέω', 'homologéo', 'literalmente "hablar lo mismo"; declarar públicamente, no solo creer en privado')] },
      { ref: '10:34-36', text: '"No crean que vine a traer paz a la tierra. No vine a traer paz sino espada... los enemigos de cada cual serán los de su propia familia."', commentary: 'Una de las declaraciones más malinterpretadas del evangelio: Jesús no celebra la división familiar, describe su consecuencia inevitable en un mundo caído. Cuando alguien cambia radicalmente desde adentro, quienes no cambian a menudo lo viven como una amenaza o una pérdida — especialmente cuando la religiosidad es parte central de la identidad familiar.', greek: [] },
      { ref: '10:37-39', text: '"El que quiere a su padre o a su madre más que a mí no es digno de mí... El que se aferre a su vida la perderá, y el que pierda su vida por mi causa la encontrará."', commentary: 'Jesús no pide dejar de amar a la familia; pide que ningún amor humano ocupe el primer lugar que le corresponde a él, como Abraham tuvo que mostrar con Isaac. Cargar la cruz en el siglo I era la imagen más cruda de muerte pública, y la paradoja que sigue —perder la vida para encontrarla— no es una figura retórica sino el principio real de cómo funciona el Reino.', greek: [] },
      { ref: '10:40-42', text: '"El que los recibe a ustedes me recibe a mí; y el que me recibe a mí recibe al que me envió... si alguien le da siquiera un vaso de agua fresca a uno de estos pequeños... no perderá su recompensa."', commentary: 'El capítulo cierra ampliando la responsabilidad más allá de los doce enviados: también los que los reciben son parte de la obra. Jesús elige deliberadamente la imagen más pequeña posible —un vaso de agua fría— para mostrar que el gesto más cotidiano de cuidado hacia quien sirve a Dios tiene peso eterno.', greek: [] },
    ],
    reflection: '¿Qué "vaso de agua fría" —un gesto pequeño y cotidiano— podrías ofrecerle hoy a alguien que sirve a Dios?',
    context: { title: 'La hospitalidad y el sostenimiento del predicador itinerante', body: 'En el siglo I, un maestro o predicador itinerante dependía por completo de la hospitalidad de quienes lo recibían: comida, alojamiento y protección a cambio de su enseñanza. Las instrucciones de Jesús de salir "sin provisiones propias" convertían esa práctica cultural en una estrategia misionera deliberada, y establecían al mismo tiempo un principio que Pablo desarrollaría después: quien trabaja en la obra de Dios tiene derecho a ser sostenido por ella.' },
  },
  11: {
    title: 'Dudas desde la cárcel y descanso para el alma',
    intro: 'Los capítulos anteriores mostraron a Jesús enseñando con autoridad, sanando y enviando a sus discípulos: todo apuntaba hacia arriba. En Mateo 11 empieza a aparecer una sombra —duda, resistencia, rechazo— y no de parte de los enemigos obvios sino de personajes inesperados, empezando por el propio Juan el Bautista.',
    blocks: [
      { ref: '11:1', text: '"Cuando Jesús terminó de dar instrucciones a sus doce discípulos, se fue de allí a enseñar y a predicar en los pueblos de Galilea."', commentary: 'En vez de detenerse a esperar resultados o descansar del esfuerzo de enseñar, Jesús continúa de inmediato. Su ministerio no tiene temporadas altas y bajas: tiene una constancia que refleja la urgencia de lo que anuncia.', greek: [] },
      { ref: '11:2-3', text: '"Juan estaba en la cárcel y, al enterarse de lo que Cristo estaba haciendo, mandó a sus discípulos a preguntarle: \'¿Eres tú el que había de venir, o debemos esperar a otro?\'"', commentary: 'Una de las escenas más humanas del evangelio: el mismo Juan que señaló a Jesús como el Cordero de Dios ahora pregunta desde la prisión si era realmente el esperado. Lo que él había anunciado era un Mesías con hacha en mano, listo para el juicio; lo que oía era que Jesús sanaba y comía con pecadores. Llevar la duda directamente a Jesús, en vez de esconderla, es en sí mismo un acto de fe madura.', greek: [] },
      { ref: '11:4-6', text: '"Vayan y cuéntenle a Juan lo que están viendo y oyendo: Los ciegos ven, los cojos andan... y a los pobres se les anuncian las buenas nuevas. Dichoso el que no tropieza por causa de mí."', commentary: 'Jesús no responde "sí, soy yo": describe hechos que son citas directas de Isaías, y deja que las Escrituras hablen. La advertencia final —dirigida también a Juan— es una invitación a no ofenderse cuando el Mesías real no coincide con el Mesías que se esperaba.', greek: [g('tropieza', 'σκανδαλίζομαι', 'skandalizomai', 'tropezar con una piedra en el camino; caer por un obstáculo inesperado')] },
      { ref: '11:7-10', text: '"¿Qué salieron a ver al desierto? ¿Una caña sacudida por el viento?... ¿A un profeta? Sí, les digo, y más que un profeta."', commentary: 'Jesús no usa la duda de Juan en su contra: lo defiende y lo exalta ante la multitud. No era una caña que se dobla con la presión —enfrentó a Herodes y terminó preso por eso— ni un hombre de comodidades: era el mensajero anunciado por Malaquías 3:1, el profeta que cierra el Antiguo Testamento y abre el Nuevo.', greek: [] },
      { ref: '11:11', text: '"Entre los nacidos de mujer no ha surgido nadie más grande que Juan el Bautista; sin embargo, el más pequeño en el reino de los cielos es más grande que él."', commentary: 'No es una contradicción sino una diferencia de posición, no de valor. Juan anunció el Reino desde afuera, como quien señala un edificio sin llegar a entrar en él; el más pequeño que vive dentro del Reino, del otro lado de la cruz y la resurrección, tiene acceso a algo que Juan solo pudo ver de lejos.', greek: [] },
      { ref: '11:12-15', text: '"El reino de los cielos ha venido avanzando contra viento y marea... Juan es el Elías que había de venir. El que tenga oídos, que oiga."', commentary: 'El período entre Juan y Jesús es de una intensidad espiritual sin precedentes: no hay lugar para la tibieza. Jesús conecta a Juan con la promesa de Malaquías de que Elías volvería antes del gran día del Señor — el plan de Dios tiene coherencia desde el Antiguo Testamento hasta su cumplimiento.', greek: [] },
      { ref: '11:16-19', text: '"¿Con qué puedo comparar a esta generación? Se parece a los niños sentados en la plaza... Pero la sabiduría queda demostrada por sus hechos."', commentary: 'Juan vino con ayuno y austeridad y lo llamaron endemoniado; Jesús vino compartiendo mesas y lo llamaron glotón y borracho. Dos estilos opuestos, el mismo rechazo: el problema nunca fue el estilo sino un corazón que buscaba excusas, no a Dios.', greek: [] },
      { ref: '11:20-22', text: '"¡Ay de ti, Corazín! ¡Ay de ti, Betsaida! Si los milagros que se hicieron en ustedes se hubieran hecho en Tiro y en Sidón, ya hace tiempo que se habrían arrepentido..."', commentary: 'Corazín y Betsaida vieron más milagros que cualquier lugar de la tierra y no se arrepintieron; Tiro y Sidón, símbolo bíblico del paganismo orgulloso, se habrían arrepentido con sacos y ceniza si hubieran visto lo mismo. La presencia de la revelación aumenta la responsabilidad de quien la recibe.', greek: [] },
      { ref: '11:23-24', text: '"Y tú, Capernaúm, ¿acaso serás levantada hasta el cielo? No, sino que descenderás hasta el abismo... será más tolerable el castigo para la región de Sodoma que para ti."', commentary: 'Capernaúm, la ciudad base del ministerio de Jesús en Galilea, recibe la advertencia más severa de las tres: ninguna ciudad de la tierra había visto tanto. Ni siquiera Sodoma, sinónimo bíblico de destrucción merecida, es comparada de forma tan desfavorable.', greek: [] },
      { ref: '11:25-26', text: '"Te alabo, Padre... porque habiendo escondido estas cosas de los sabios e instruidos, se las has revelado a los que son como niños."', commentary: 'Después de denunciar a las ciudades, Jesús ora en alabanza, no en resignación amarga. Los "sabios e instruidos" —fariseos y escribas con toda la formación necesaria— no reconocieron al Mesías; los "pequeños" lo recibieron sin pretensiones. No es un elogio a la ignorancia: es que el conocimiento propio, cuando produce orgullo, cierra la capacidad de recibir.', greek: [g('los que son como niños', 'νήπιοι', 'nēpioi', 'niños pequeños; los que no tienen pretensiones de conocimiento y reciben sin calcular')] },
      { ref: '11:27', text: '"Todas las cosas me han sido entregadas por mi Padre. Nadie conoce al Hijo sino el Padre, y nadie conoce al Padre sino el Hijo y aquel a quien el Hijo tenga a bien revelárselo."', commentary: 'Una de las declaraciones cristológicamente más densas de los evangelios: autoridad total entregada (la misma que reaparecerá en 28:18), un conocimiento mutuo entre Padre e Hijo que ninguna criatura puede penetrar desde afuera, y un acceso al Padre que pasa necesariamente por el Hijo — el fundamento de "nadie viene al Padre sino por mí" en Juan 14:6.', greek: [] },
      { ref: '11:28-30', text: '"Vengan a mí todos ustedes que están cansados y agobiados, y yo les daré descanso. Carguen con mi yugo y aprendan de mí, pues yo soy apacible y humilde de corazón... mi yugo es suave y mi carga es liviana."', commentary: 'Justo después de hablar de juicio y ciudades que rechazaron los milagros, Jesús abre los brazos con una de las invitaciones más amplias del evangelio. Los cansados y agobiados eran, en ese contexto, los que vivían bajo el peso de los 613 mandamientos de la Halajá sin nunca saber si habían hecho lo suficiente. El descanso que ofrece no es ausencia de yugo sino un yugo compartido con él — y la única autodescripción directa de Jesús en todo el evangelio: manso y humilde de corazón.', greek: [g('cansados', 'κοπιάω', 'kopiáo', 'el agotamiento que deja sin fuerzas, propio de un trabajo pesado'), g('agobiados', 'φορτίζω', 'phortízo', 'estar cargado con un peso que aplasta'), g('descanso', 'ἀνάπαυσις', 'anápausis', 'reposo activo; no solo ausencia de esfuerzo sino presencia de paz'), g('apacible', 'πραΰς', 'praus', 'manso; fuerza sometida bajo control, la misma palabra de las bienaventuranzas'), g('humilde', 'ταπεινός', 'tapeinós', 'de baja posición, en el sentido de no exigir posición propia')] },
    ],
    reflection: 'Como Juan desde la cárcel, ¿tenés alguna duda honesta que preferís esconder en vez de llevarle directamente a Jesús?',
    context: { title: 'La fortaleza de Maqueronte y la prisión de Juan', body: 'Juan el Bautista estaba preso en Maqueronte, una fortaleza en el desierto al este del Mar Muerto, bajo el poder de Herodes Antipas, a quien había confrontado públicamente por su matrimonio adúltero. Encadenado, aislado y consciente de que su ejecución se acercaba, la pregunta que manda a hacerle a Jesús no nace de un retiro espiritual tranquilo sino de la oscuridad real de una celda — lo que hace su fe, y su duda, mucho más humanas.' },
  },
};

export const CHARACTERS: Character[] = [
  { name: 'Simón Pedro', category: 'Discípulos', chapters: [4, 10, 14, 16, 26], blurb: 'Pescador de Galilea, impulsivo y apasionado. El primero en declarar que Jesús es el Cristo (16:16) y, líneas después, reprendido como "Satanás" (16:23). Negará a Jesús tres veces y será restaurado — la demostración más clara de que el llamado no depende de la perfección.' },
  { name: 'Andrés', category: 'Discípulos', chapters: [4, 10], blurb: 'Hermano de Pedro, también pescador. Antes fue discípulo de Juan el Bautista. Aparece repetidamente como el que conecta a otros con Jesús: trae a Pedro, trae al niño de los panes y los peces, trae a los griegos que quieren ver a Jesús.' },
  { name: 'Santiago (hijo de Zebedeo)', category: 'Discípulos', chapters: [4, 10, 17], blurb: 'Uno de los "hijos del trueno", apodo por su temperamento. Junto a su hermano Juan pidió que cayera fuego sobre una aldea samaritana. Será el primer apóstol martirizado.' },
  { name: 'Juan (hijo de Zebedeo)', category: 'Discípulos', chapters: [4, 10, 17], blurb: 'El otro "hijo del trueno", transformado en "el apóstol del amor". Autor del cuarto evangelio, tres cartas y el Apocalipsis. Tradicionalmente el único apóstol que no murió mártir.' },
  { name: 'Felipe', category: 'Discípulos', chapters: [10], blurb: 'De Betsaida. Pensador práctico y calculador (hace cálculos ante la multiplicación de los panes), pero también un buscador genuino: "Muéstranos al Padre y con eso nos basta".' },
  { name: 'Bartolomé (Natanael)', category: 'Discípulos', chapters: [10], blurb: 'Su primera reacción a Jesús fue escéptica: "¿De Nazaret puede salir algo bueno?". Al encontrarse con él, su escepticismo se convirtió en: "Tú eres el Hijo de Dios, el Rey de Israel".' },
  { name: 'Mateo (Leví)', category: 'Discípulos', chapters: [9, 10], blurb: 'Autor de este evangelio. Recaudador de impuestos, colaborador de Roma, despreciado por su propio pueblo. Jesús lo llamó con dos palabras y lo dejó todo de inmediato.' },
  { name: 'Tomás', category: 'Discípulos', chapters: [10], blurb: 'Conocido como "el que dudó", descripción parcial e injusta: fue quien dijo "vayamos también nosotros para morir con él". Su confesión ante el resucitado fue la más alta del evangelio: "¡Señor mío y Dios mío!".' },
  { name: 'Santiago (hijo de Alfeo)', category: 'Discípulos', chapters: [10], blurb: '"Santiago el menor", para distinguirlo del hijo de Zebedeo. Poco se sabe de él directamente; su presencia fiel y silenciosa es, en sí misma, un testimonio.' },
  { name: 'Tadeo (Judas, hijo de Santiago)', category: 'Discípulos', chapters: [10], blurb: 'Le hace a Jesús una de las preguntas más humanas de la última cena: "¿Por qué estás dispuesto a manifestarte a nosotros y no al mundo?".' },
  { name: 'Simón el Zelote', category: 'Discípulos', chapters: [10], blurb: 'Perteneció al movimiento zelote, violentamente opuesto a Roma y a todo colaborador. Que comparta equipo con Mateo, recaudador de impuestos, es en sí mismo una señal del Reino.' },
  { name: 'Judas Iscariote', category: 'Discípulos', chapters: [10, 26, 27], blurb: 'El que entregará a Jesús. Tesorero del grupo; según Juan 12:6 robaba del dinero confiado. Desilusionado con el tipo de Reino que Jesús construía. Jesús lo eligió sabiendo lo que haría.' },
  { name: 'María', category: 'Familia de Jesús', chapters: [1, 2], blurb: 'Su embarazo antes del matrimonio la exponía a la deshonra pública y, legalmente, a un posible repudio. Su disposición ("hágase conmigo conforme a tu palabra") es un acto de fe radical dentro de una cultura de honor y vergüenza.' },
  { name: 'José', category: 'Familia de Jesús', chapters: [1, 2], blurb: 'Descrito como "justo": pudo exponer a María públicamente y eligió no hacerlo. Obedece cada instrucción del ángel sin registro de una sola palabra suya en el texto — un hombre de acción silenciosa.' },
  { name: 'Fariseos', category: 'Autoridades religiosas', chapters: [5, 9, 12, 15, 23], blurb: 'Movimiento laico dedicado a la observancia meticulosa de la Ley y su tradición oral (Halajá). Buscaban la santidad mediante la separación; su conflicto con Jesús es, sobre todo, sobre dónde está el verdadero corazón de la Ley.' },
  { name: 'Saduceos', category: 'Autoridades religiosas', chapters: [3, 16, 22], blurb: 'Aristocracia sacerdotal vinculada al templo, con poder político bajo Roma. Rechazaban la resurrección y la tradición oral, aceptando solo la Torá escrita.' },
  { name: 'Escribas', category: 'Autoridades religiosas', chapters: [5, 7, 9], blurb: 'Expertos legales que copiaban, interpretaban y enseñaban la Ley. Su autoridad derivaba de la tradición acumulada; la de Jesús, notaron las multitudes, era distinta "porque enseñaba como quien tiene autoridad".' },
  { name: 'Caifás', category: 'Autoridades religiosas', chapters: [26], blurb: 'Sumo sacerdote durante el juicio de Jesús. Preside el consejo (Sanedrín) que declara a Jesús merecedor de muerte por blasfemia.' },
  { name: 'Herodes el Grande', category: 'Autoridades políticas', chapters: [2], blurb: 'Rey de Judea bajo mandato romano, conocido por su paranoia y crueldad. Ordena la matanza de los niños de Belén al sentir amenazado su trono por el nacimiento de un "rey de los judíos".' },
  { name: 'Herodes Antipas', category: 'Autoridades políticas', chapters: [14], blurb: 'Hijo de Herodes el Grande, tetrarca de Galilea. Manda decapitar a Juan el Bautista y más tarde se inquieta al oír de Jesús, temiendo que fuera Juan resucitado.' },
  { name: 'Poncio Pilato', category: 'Autoridades políticas', chapters: [27], blurb: 'Gobernador romano de Judea. Reconoce la inocencia de Jesús ante el Sanedrín pero cede a la presión política, lavándose las manos del veredicto.' },
  { name: 'Juan el Bautista', category: 'Otros', chapters: [3, 11, 14], blurb: 'El mensajero anunciado por Malaquías siglos antes. Predica arrepentimiento en el desierto y bautiza a Jesús. Desde la prisión envía a preguntar si Jesús es realmente "el que había de venir".' },
  { name: 'La mujer cananea', category: 'Otros', chapters: [15], blurb: 'Extranjera y de otra religión, insiste ante el silencio inicial de Jesús. Recibe la calificación de fe más alta del evangelio: "grande es tu fe".' },
  { name: 'El centurión romano', category: 'Otros', chapters: [8], blurb: 'Oficial del ejército de ocupación. Su fe en la autoridad de la sola palabra de Jesús ("solamente di la palabra") es señalada como mayor que cualquiera encontrada en Israel.' },
];

