export const CONTEXT_TOPICS: ContextTopic[] = [
  { id: 'c1', theme: 'Vida judía', title: 'Los 400 años de silencio', body: 'Malaquías, el último profeta del Antiguo Testamento, escribió alrededor del 430–400 a.C. — unos 400 años antes del nacimiento de Jesús. Su mensaje confronta a un pueblo que cumplía rituales con el corazón frío, y cierra con una promesa: Dios enviará un mensajero que preparará el camino del Señor. Después viene el silencio: sin profetas ni nueva revelación escrita, hasta que Dios vuelve a hablar en Juan el Bautista y, finalmente, en Jesús.' },
  { id: 'c2', theme: 'Vida judía', title: 'La Halajá y los 613 mandamientos', body: 'Escribas y fariseos desarrollaron una tradición oral enorme para "cercar" la Ley y evitar violarla en cualquier detalle. Llegaron a contar 613 mandamientos derivados del texto bíblico. El problema no era amar la Ley, sino que con el tiempo la obediencia se volvió externa y performativa.' },
  { id: 'c3', theme: 'Geografía', title: 'Galilea y Judea', body: 'El ministerio de Jesús recorre dos regiones con carácter distinto: Galilea, rural, densamente poblada alrededor del lago, más alejada del control religioso estricto de Jerusalén; y Judea, centrada en Jerusalén y el Templo, sede del poder religioso y político. El "camino a Jerusalén" que ocupa buena parte del evangelio es también un viaje del margen al centro del conflicto.' },
  { id: 'c4', theme: 'Política romana', title: 'El oficio del recaudador de impuestos', body: 'Roma fijaba un monto de tributo y el recaudador podía cobrar de más para quedarse con la diferencia — un oficio asociado a abuso, corrupción e injusticia. Al tratar con gentiles y dinero impuro, el recaudador quedaba también ritualmente impuro. Despreciado por los judíos como traidor y usado por Roma sin ser considerado uno de los suyos, Mateo escribe su evangelio desde esa doble marginación.' },
  { id: 'c5', theme: 'Prácticas religiosas', title: 'Limosna, oración y ayuno públicos', body: 'Las tres prácticas centrales de la piedad judía eran también las más visibles socialmente: dar limosna en la sinagoga, orar de pie en momentos fijos, ayunar mostrando el rostro demacrado. El reconocimiento comunitario por la piedad era tan valorado como la piedad misma, lo que Jesús señala directamente en Mateo 6.' },
  { id: 'c6', theme: 'Prácticas religiosas', title: 'El sábado (shabbat)', body: 'Junto con la circuncisión, el sábado era la marca de identidad judía más celosamente guardada, conmemorando el descanso de Dios en la creación. Los debates sobre qué constituía "trabajo" en sábado eran intensos y detallados, y estaban en el centro de buena parte de la tensión entre Jesús y los fariseos.' },
  { id: 'c7', theme: 'Vida judía', title: 'Genealogías, honor y gematría', body: 'Una genealogía servía para demostrar origen, honor y herencia, no solo parentesco. En la numerología hebrea (gematría), cada letra tiene un valor numérico: el nombre David (דוד) suma exactamente 14, lo que explica la estructura de tres bloques de catorce generaciones con la que Mateo abre su evangelio.' },
  { id: 'c8', theme: 'Política romana', title: 'Herodes el Grande: un trono sostenido por el miedo', body: 'Idumeo y sin linaje davídico, Herodes gobernaba por designación romana y sabía que su autoridad no estaba legitimada ante el pueblo judío. Llegó a ordenar la muerte de esposas, hijos y parientes cercanos ante la mínima sospecha de conspiración — el trasfondo de su reacción ante la noticia de "el rey de los judíos" en Mateo 2.' },
  { id: 'c9', theme: 'Geografía', title: 'Los magos de oriente y la astronomía antigua', body: 'Los "magos" del oriente eran sabios y astrónomos, probablemente de Persia o Babilonia, con acceso a textos judíos desde el exilio siglos antes. Entre los años 7 y 6 a.C. se registró una triple conjunción de Júpiter y Saturno en la constelación de Piscis, un fenómeno poco frecuente que pudo leerse como el anuncio de un nuevo rey en Israel.' },
];
